export default NameInput;

import { GoogleGenAI, Modality } from "@google/genai";
import { Language, Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

let audioContext: AudioContext | null = null;
let currentSource: AudioBufferSourceNode | null = null;

const initAudioContext = () => {
  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  }
  return audioContext;
};

function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const stopSpeech = () => {
  if (currentSource) {
    try {
      currentSource.stop();
    } catch (e) {}
    currentSource = null;
  }
};

export const speakText = async (text: string): Promise<boolean> => {
  stopSpeech();
  const ctx = initAudioContext();

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' }, // Deep, masculine host voice
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioBuffer = await decodeAudioData(
        decodeBase64(base64Audio),
        ctx,
        24000,
        1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
      currentSource = source;

      return new Promise((resolve) => {
        source.onended = () => {
          currentSource = null;
          resolve(true);
        };
      });
    }
  } catch (error) {
    console.error("TTS Error:", error);
  }
  return false;
};

export const speakQuestionOnly = async (level: number, question: Question, lang: Language, playerName: string) => {
  const isHindi = lang === Language.HINDI;
  const prompt = isHindi 
    ? `${playerName} जी, आपका अगला सवाल ₹${level === 1 ? '5,000' : 'इतने'} के लिए यह रहा: ${question.text}।`
    : `${playerName}, your next question for level ${level} is: ${question.text}.`;

  return speakText(prompt);
};

export const speakOptionsIntro = async (lang: Language) => {
  const isHindi = lang === Language.HINDI;
  const prompt = isHindi ? "अब आपके विकल्प ये रहे..." : "And here are your options...";
  return speakText(prompt);
};

export const speakOptionsOnly = async (question: Question, lang: Language) => {
  const isHindi = lang === Language.HINDI;
  const prompt = isHindi 
    ? `विकल्प ए: ${question.options.A}। विकल्प बी: ${question.options.B}। विकल्प सी: ${question.options.C}। विकल्प डी: ${question.options.D}।`
    : `Option A: ${question.options.A}. Option B: ${question.options.B}. Option C: ${question.options.C}. Option D: ${question.options.D}.`;

  return speakText(prompt);
};

export const speakLifelineSuggestion = async (lang: Language) => {
  const isHindi = lang === Language.HINDI;
  const prompt = isHindi 
    ? "अगर आपको कठिनाई हो रही है, तो आप अपनी लाइफलाइन का उपयोग कर सकते हैं।" 
    : "If you're having difficulty, you may consider using a lifeline.";
  return speakText(prompt);
};

import React, { useState, useEffect, useRef } from 'react';
import { Question, Language } from '../types';
import { recognizeVoiceAnswer } from '../services/gemini';

interface Props {
  question: Question;
  language: Language;
  hiddenOptions: string[];
  isDoubleDipActive: boolean;
  showOptions: boolean;
  isSpeaking: boolean;
  onAnswer: (correct: boolean, isFirstAttemptOfDoubleDip: boolean) => void;
  onRepeat: () => void;
}

const QuizArea: React.FC<Props> = ({ 
  question, language, hiddenOptions, isDoubleDipActive, showOptions, isSpeaking, onAnswer, onRepeat 
}) => {
  const [selected, setSelected] = useState<string | null>(null);
  const [locked, setLocked] = useState(false);
  const [showResult, setShowResult] = useState(false);
  const [failedOptions, setFailedOptions] = useState<string[]>([]);

  const [isRecording, setIsRecording] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    setSelected(null);
    setLocked(false);
    setShowResult(false);
    setFailedOptions([]);
  }, [question]);

  const handleOptionClick = (key: string) => {
    if (!locked && !showResult && !hiddenOptions.includes(key) && !failedOptions.includes(key)) {
      setSelected(key);
    }
  };

  const lockAnswer = () => {
    if (!selected) return;
    setLocked(true);

    setTimeout(() => {
      const isCorrect = selected === question.correctAnswer;
      setShowResult(true);

      if (isCorrect) {
        setTimeout(() => onAnswer(true, false), 2500);
      } else {
        if (isDoubleDipActive && failedOptions.length === 0) {
          setTimeout(() => {
            setFailedOptions(prev => [...prev, selected]);
            setSelected(null);
            setLocked(false);
            setShowResult(false);
            onAnswer(false, true);
          }, 1500);
        } else {
          setTimeout(() => onAnswer(false, false), 3500);
        }
      }
    }, 2000);
  };

  const startRecording = async () => {
    if (locked || showResult || isRecording || isTranscribing) return;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64String = (reader.result as string).split(',')[1];
          if (!base64String) return;

          setIsTranscribing(true);
          const recognizedOption = await recognizeVoiceAnswer(base64String, 'audio/webm', language);
          setIsTranscribing(false);

          if (recognizedOption && !hiddenOptions.includes(recognizedOption) && !failedOptions.includes(recognizedOption)) {
            setSelected(recognizedOption);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);

      setTimeout(() => {
        if (mediaRecorderRef.current?.state === 'recording') {
          stopRecording();
        }
      }, 3000);

    } catch (err) {
      console.error("Microphone access denied or error:", err);
      alert(language === Language.HINDI ? "माइक्रोफ़ोन एक्सेस की आवश्यकता है।" : "Microphone access is required.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const getOptionClass = (key: string) => {
    if (hiddenOptions.includes(key)) return 'opacity-0 pointer-events-none cursor-default';
    if (failedOptions.includes(key)) return 'opacity-40 grayscale cursor-not-allowed bg-red-950/20';

    if (showResult) {
      if (key === question.correctAnswer) {
        return 'option-correct scale-[1.05] z-10 shadow-[0_0_30px_#22c55e]';
      }
      if (key === selected && selected !== question.correctAnswer) {
        return 'option-wrong shadow-[0_0_30px_#ef4444] scale-[0.98]';
      }
      return 'opacity-20 grayscale-[0.9] blur-[1px]';
    }

    if (selected === key) {
      return locked 
        ? 'bg-gradient-to-r from-orange-600 to-yellow-500 border-white animate-pulse shadow-[0_0_25px_rgba(234,88,12,0.9)] scale-[1.03] z-10' 
        : 'bg-orange-500 border-white shadow-[0_0_15px_rgba(234,88,12,0.5)] scale-[1.02]';
    }

    return 'hover:bg-blue-900/40 border-[#d4af37]/40';
  };

  const isHindi = language === Language.HINDI;

  return (
    <div className="flex flex-col items-center justify-center p-2 md:p-8 space-y-4 md:space-y-6 w-full max-w-5xl mx-auto">

      {/* Host Avatar Section */}
      <div className="flex flex-col items-center mb-2 animate-fade-in">
        <div className={`relative w-20 h-20 md:w-28 md:h-28 rounded-full border-4 border-[#d4af37] overflow-hidden bg-blue-900 shadow-[0_0_20px_rgba(212,175,55,0.3)] transition-all ${isSpeaking ? 'scale-110 shadow-[0_0_40px_rgba(212,175,55,0.6)]' : ''}`}>
          {/* Conceptual Image of an elderly intelligent Indian male host */}
          <img 
            src="https://api.dicebear.com/7.x/avataaars/svg?seed=Host&skinColor=ae5d29&topType=shortHair&hairColor=70b2d9&facialHairType=beardLight&facialHairColor=white" 
            alt="AI Host" 
            className="w-full h-full object-cover"
          />
          {isSpeaking && (
             <div className="absolute inset-0 bg-[#d4af37]/10 animate-pulse"></div>
          )}
        </div>
        <div className="mt-2 bg-black/60 px-4 py-0.5 rounded-full border border-[#d4af37]/40">
           <span className="text-[10px] gold-text font-black uppercase tracking-widest">{isHindi ? 'क्विज मास्टर' : 'QUIZ MASTER'}</span>
        </div>
      </div>

      {/* Question Box */}
      <div className="w-full p-6 md:p-12 bg-black/80 border-2 border-[#d4af37] rounded-2xl md:rounded-3xl text-center shadow-[0_0_40px_rgba(212,175,55,0.15)] relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#d4af37] to-transparent"></div>
        <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-[#001a33] px-6 py-0.5 border border-[#d4af37] rounded-full text-[10px] gold-text font-black uppercase tracking-[0.3em] whitespace-nowrap z-20">
          {isHindi ? 'प्रश्न' : 'Question'}
        </div>
        <h2 className="text-xl md:text-3xl lg:text-4xl font-bold text-white leading-tight md:leading-relaxed drop-shadow-lg relative z-10">
          {question.text}
        </h2>
      </div>

      {/* Voice & Replay Controls */}
      <div className="flex items-center justify-center space-x-6 md:space-x-12">
        <div className="flex flex-col items-center">
          <button
            onClick={isRecording ? stopRecording : startRecording}
            disabled={locked || showResult || isTranscribing}
            className={`relative group w-14 h-14 md:w-16 md:h-16 flex items-center justify-center rounded-full transition-all duration-300 border-2 ${
              isRecording 
                ? 'bg-red-500 border-white shadow-[0_0_20px_#ef4444] animate-mic-pulse' 
                : isTranscribing 
                  ? 'bg-blue-600 border-blue-400 animate-spin-slow shadow-[0_0_20px_#3b82f6]'
                  : 'bg-black/60 border-[#d4af37]/60 hover:border-[#d4af37] hover:scale-110 shadow-[0_0_15px_rgba(212,175,55,0.2)]'
            } ${locked || showResult ? 'opacity-20 cursor-not-allowed' : ''}`}
          >
            {isTranscribing ? <i className="fas fa-circle-notch animate-spin text-white"></i> : isRecording ? <i className="fas fa-stop text-white"></i> : <i className="fas fa-microphone gold-text group-hover:text-white"></i>}
          </button>
          <span className="text-[8px] md:text-[10px] gold-text font-bold uppercase tracking-widest mt-2">{isHindi ? 'उत्तर दें' : 'Answer'}</span>
        </div>

        <div className="flex flex-col items-center">
          <button
            onClick={onRepeat}
            disabled={locked || showResult || isSpeaking}
            className={`w-14 h-14 md:w-16 md:h-16 flex items-center justify-center rounded-full border-2 border-[#d4af37]/60 bg-black/60 transition-all hover:scale-110 hover:border-[#d4af37] ${isSpeaking || locked || showResult ? 'opacity-20 cursor-not-allowed' : ''}`}
          >
            <i className="fas fa-redo gold-text"></i>
          </button>
          <span className="text-[8px] md:text-[10px] gold-text font-bold uppercase tracking-widest mt-2">{isHindi ? 'फिर से सुनें' : 'Repeat'}</span>
        </div>
      </div>

      {/* Options Grid - Hidden initially */}
      <div className={`grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6 w-full px-2 max-w-4xl transition-all duration-1000 ${showOptions ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10 pointer-events-none'}`}>
        {Object.entries(question.options).map(([key, value]) => (
          <button
            key={key}
            onClick={() => handleOptionClick(key)}
            disabled={locked || showResult || hiddenOptions.includes(key) || failedOptions.includes(key)}
            className={`option-button group flex items-center px-8 md:px-12 py-4 md:py-6 text-white text-base md:text-xl font-bold min-h-[60px] md:min-h-[80px] transition-all duration-300 ${getOptionClass(key)}`}
          >
            <span className={`mr-4 md:mr-6 font-black text-xl md:text-2xl transition-colors duration-300 ${selected === key || (showResult && (key === selected || key === question.correctAnswer)) ? 'text-white' : 'gold-text'}`}>
              {key}:
            </span>
            <span className="text-left leading-tight line-clamp-2 md:line-clamp-3 flex-grow">{value}</span>
          </button>
        ))}
      </div>

      {/* Action Area */}
      <div className="h-20 md:h-24 flex items-center justify-center w-full">
        {selected && !locked && !showResult && (
          <button
            onClick={lockAnswer}
            className="group relative bg-gradient-to-r from-orange-600 via-orange-500 to-orange-400 text-white font-black py-4 px-14 md:px-24 rounded-full text-xl md:text-3xl shadow-[0_15px_40px_rgba(234,88,12,0.4)] transition-all transform hover:scale-110 active:scale-95 animate-bounce uppercase tracking-tighter overflow-hidden"
          >
            <span className="relative z-10">{isHindi ? 'लॉक किया जाए!' : 'Lock Kiya Jaye!'}</span>
            <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700 skew-x-12"></div>
          </button>
        )}
        {locked && !showResult && (
          <div className="flex flex-col items-center">
            <div className="text-orange-400 font-black text-2xl md:text-4xl animate-pulse uppercase italic tracking-[0.2em]">
              {isHindi ? 'चेक कर रहे हैं...' : 'Checking...'}
            </div>
          </div>
        )}
        {showResult && (
          <div className={`font-black text-3xl md:text-5xl animate-scale-in uppercase tracking-tighter drop-shadow-2xl text-center ${selected === question.correctAnswer ? 'text-green-400' : 'text-red-500'}`}>
            {selected === question.correctAnswer ? (isHindi ? 'सही जवाब!' : 'Correct!') : (isHindi ? 'गलत जवाब!' : 'Wrong!')}
          </div>
        )}
      </div>

      {/* Explanation Box */}
      {showResult && (
        <div className="w-full max-w-3xl p-5 md:p-6 bg-black/60 border-l-4 border-[#d4af37] rounded-xl text-white animate-fade-in backdrop-blur-xl shadow-2xl">
          <p className="text-sm md:text-lg leading-relaxed italic text-blue-50">"{question.explanation}"</p>
        </div>
      )}
    </div>
  );
};

export default QuizArea;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import LanguageSelection from './components/LanguageSelection';
import NameInput from './components/NameInput';
import Disclaimer from './components/Disclaimer';
import Sidebar from './components/Sidebar';
import QuizArea from './components/QuizArea';
import Lifelines from './components/Lifelines';
import GameOver from './components/GameOver';
import { Language, GameStatus, Question, Lifelines as LifelinesType, PollData } from './types';
import { fetchQuestion } from './services/gemini';
import { getTimerForLevel, MONEY_TREE } from './constants';
import { 
  stopSpeech, 
  speakQuestionOnly, 
  speakOptionsIntro, 
  speakOptionsOnly, 
  speakLifelineSuggestion 
} from './services/tts';

const App: React.FC = () => {
  const [status, setStatus] = useState<GameStatus>(GameStatus.NAME_INPUT);
  const [playerName, setPlayerName] = useState('');
  const [language, setLanguage] = useState<Language>(Language.ENGLISH);
  const [level, setLevel] = useState(1);
  const [question, setQuestion] = useState<Question | null>(null);
  const [loading, setLoading] = useState(false);
  const [timeLeft, setTimeLeft] = useState<number | null>(null);
  const [maxTime, setMaxTime] = useState<number | null>(null);
  const [hiddenOptions, setHiddenOptions] = useState<string[]>([]);
  const [pollData, setPollData] = useState<PollData | null>(null);
  const [isDoubleDipActive, setIsDoubleDipActive] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isVoiceEnabled, setIsVoiceEnabled] = useState(true);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [showOptions, setShowOptions] = useState(false);
  const [lifelineSuggested, setLifelineSuggested] = useState(false);
  const [lifelines, setLifelines] = useState<LifelinesType>({
    fiftyFifty: true,
    audiencePoll: true,
    doubleDip: true,
    flipQuestion: true
  });

  const timerRef = useRef<any>(null);

  const startSpeechSequence = useCallback(async (q: Question, l: number, lang: Language, name: string) => {
    setIsSpeaking(true);
    setShowOptions(false);

    // 1. Speak Question
    await speakQuestionOnly(l, q, lang, name);

    // 2. Short pause & Intro options
    await speakOptionsIntro(lang);

    // 3. Reveal options visually immediately after host says "Here are your options"
    setShowOptions(true);

    // 4. Speak the options list
    await speakOptionsOnly(q, lang);

    setIsSpeaking(false);
  }, []);

  const loadQuestion = async (currLevel: number, lang: Language) => {
    stopSpeech();
    setIsSpeaking(false);
    setLoading(true);
    setShowOptions(false);
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);
    setIsSidebarOpen(false);
    setLifelineSuggested(false);

    try {
      const q = await fetchQuestion(currLevel, lang);
      const initialTime = getTimerForLevel(currLevel);

      setQuestion(q);
      setMaxTime(initialTime);
      setTimeLeft(initialTime);

      setLoading(false); // End loading screen before speaking

      if (isVoiceEnabled) {
        startSpeechSequence(q, currLevel, lang, playerName);
      } else {
        setShowOptions(true);
      }
    } catch (error) {
      console.error("Failed to load question", error);
      setLoading(false);
    }
  };

  useEffect(() => {
    if (status === GameStatus.PLAYING && timeLeft !== null && timeLeft > 0 && !loading) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev === null) return null;

          // Lifeline Suggestion Logic: after 15 seconds have passed (or if time left <= 30 for 45s timer)
          const timeElapsed = (maxTime || 0) - (prev - 1);
          const hasAvailableLifelines = Object.values(lifelines).some(v => v === true);

          if (timeElapsed >= 15 && !lifelineSuggested && hasAvailableLifelines && isVoiceEnabled && !isSpeaking) {
            setLifelineSuggested(true);
            speakLifelineSuggestion(language);
          }

          if (prev <= 1) {
            clearInterval(timerRef.current);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else if (status === GameStatus.PLAYING && timeLeft === 0 && !loading) {
      handleAnswer(false, false);
    }

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [status, timeLeft, loading, lifelineSuggested, lifelines, language, isVoiceEnabled, isSpeaking, maxTime]);

  const handleNameSubmit = (name: string) => {
    setPlayerName(name);
    setStatus(GameStatus.LANGUAGE_SELECT);
  };

  const handleLanguageSelect = (lang: Language) => {
    setLanguage(lang);
    setStatus(GameStatus.DISCLAIMER);
  };

  const handleStartGame = () => {
    setStatus(GameStatus.PLAYING);
    loadQuestion(1, language);
  };

  const handleAnswer = (isCorrect: boolean, isFirstAttemptOfDoubleDip: boolean) => {
    stopSpeech();
    setIsSpeaking(false);
    if (isFirstAttemptOfDoubleDip) return;
    if (timerRef.current) clearInterval(timerRef.current);

    if (isCorrect) {
      setTimeout(() => {
        if (level === 15) {
          setStatus(GameStatus.WON);
        } else {
          const nextLevel = level + 1;
          setLevel(nextLevel);
          loadQuestion(nextLevel, language);
        }
      }, 2000);
    } else {
      setTimeout(() => {
        setStatus(GameStatus.LOST);
      }, 1500);
    }
  };

  const useLifeline = (type: keyof LifelinesType) => {
    if (!question || loading) return;
    stopSpeech();
    setIsSpeaking(false);

    setLifelines(prev => ({ ...prev, [type]: false }));

    if (type === 'fiftyFifty') {
      const incorrect = Object.keys(question.options).filter(k => k !== question.correctAnswer);
      const shuffled = incorrect.sort(() => 0.5 - Math.random());
      setHiddenOptions(shuffled.slice(0, 2));
    } else if (type === 'audiencePoll') {
      const correctKey = question.correctAnswer as keyof PollData;
      const data: PollData = { A: 0, B: 0, C: 0, D: 0 };
      const visibleKeys = (['A', 'B', 'C', 'D'] as (keyof PollData)[]).filter(k => !hiddenOptions.includes(k));
      const correctWeight = Math.floor(Math.random() * 20) + 65;
      data[correctKey] = correctWeight;
      let remainingPercent = 100 - correctWeight;
      const otherVisibleKeys = visibleKeys.filter(k => k !== correctKey);
      if (otherVisibleKeys.length > 0) {
        otherVisibleKeys.forEach((key, index) => {
          if (index === otherVisibleKeys.length - 1) {
            data[key] = remainingPercent;
          } else {
            const val = Math.floor(Math.random() * remainingPercent);
            data[key] = val;
            remainingPercent -= val;
          }
        });
      }
      setPollData(data);
    } else if (type === 'doubleDip') {
      setIsDoubleDipActive(true);
    } else if (type === 'flipQuestion') {
      loadQuestion(level, language);
    }
  };

  const restartGame = () => {
    stopSpeech();
    if (timerRef.current) clearInterval(timerRef.current);
    setLevel(1);
    setQuestion(null);
    setTimeLeft(null);
    setMaxTime(null);
    setLoading(false);
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);
    setIsSidebarOpen(false);
    setIsSpeaking(false);
    setShowOptions(false);
    setLifelineSuggested(false);
    setStatus(GameStatus.NAME_INPUT);
    setLifelines({ fiftyFifty: true, audiencePoll: true, doubleDip: true, flipQuestion: true });
  };

  const isHindi = language === Language.HINDI;

  if (status === GameStatus.NAME_INPUT) {
    return <NameInput onNameSubmit={handleNameSubmit} />;
  }

  if (status === GameStatus.LANGUAGE_SELECT) {
    return <LanguageSelection onSelect={handleLanguageSelect} />;
  }

  if (status === GameStatus.WON || status === GameStatus.LOST) {
    return <GameOver isWon={status === GameStatus.WON} levelReached={level} language={language} onRestart={restartGame} />;
  }

  const currentLevelAmount = MONEY_TREE.find(l => l.id === level)?.amount || "₹0";
  const radius = 42;
  const circumference = 2 * Math.PI * radius;
  const progressOffset = timeLeft !== null && maxTime !== null ? circumference - (timeLeft / maxTime) * circumference : 0;

  return (
    <div className="min-h-screen kbc-bg flex flex-col md:flex-row relative overflow-hidden text-white">
      {status === GameStatus.DISCLAIMER && (
        <Disclaimer language={language} onStart={handleStartGame} />
      )}

      <div className={`fixed inset-0 z-[120] md:hidden transition-opacity duration-300 ${isSidebarOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
        <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}></div>
        <div className={`absolute left-0 top-0 bottom-0 w-[80%] max-w-sm bg-[#000d1a] shadow-2xl transition-transform duration-300 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
           <div className="flex items-center justify-between p-4 border-b border-[#d4af37]/30 bg-black/40">
             <h3 className="gold-text font-black uppercase tracking-widest">{isHindi ? 'धन वृक्ष' : 'Money Tree'}</h3>
             <button onClick={() => setIsSidebarOpen(false)} className="text-[#d4af37] text-2xl p-2"><i className="fas fa-times"></i></button>
           </div>
           <div className="h-[calc(100%-64px)] overflow-y-auto">
             <Sidebar currentLevel={level} />
           </div>
        </div>
      </div>

      <div className="flex-grow flex flex-col relative min-h-screen z-10">
        <header className="w-full flex justify-between items-center px-4 md:px-6 py-3 md:py-5 bg-black/60 border-b border-[#d4af37]/30 backdrop-blur-md sticky top-0 z-[50]">
          <div className="flex items-center space-x-3">
            <button onClick={() => setIsSidebarOpen(true)} className="md:hidden text-[#d4af37] text-xl p-2 bg-blue-900/30 rounded-lg">
              <i className="fas fa-bars"></i>
            </button>
            <div className="flex flex-col">
              <span className="text-gray-400 font-bold uppercase text-[8px] md:text-xs tracking-widest">{playerName || 'PLAYER'} • LVL {level}</span>
              <span className="gold-text font-black text-sm md:text-xl leading-none">{currentLevelAmount}</span>
            </div>
          </div>

          <div className="flex items-center space-x-2 md:space-x-6">
            <button 
              onClick={() => setIsVoiceEnabled(!isVoiceEnabled)}
              className={`w-10 h-10 md:w-12 md:h-12 rounded-full flex items-center justify-center transition-all ${isVoiceEnabled ? 'bg-[#d4af37] text-black shadow-[0_0_15px_rgba(212,175,55,0.5)]' : 'bg-gray-800 text-gray-400'}`}
              title={isHindi ? 'आवाज विकल्प' : 'Voice Options'}
            >
              <i className={`fas ${isVoiceEnabled ? 'fa-volume-up' : 'fa-volume-mute'} text-lg`}></i>
            </button>
            <div className="hidden md:block">
              <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || status !== GameStatus.PLAYING} />
            </div>
          </div>

          <div className="flex items-center">
             {timeLeft !== null && status === GameStatus.PLAYING && !loading ? (
              <div className={`relative w-12 h-12 md:w-20 md:h-20 flex items-center justify-center rounded-full ${timeLeft <= 10 ? 'animate-timer-critical' : 'animate-timer-pulse'}`}>
                <svg className="absolute inset-0 transform -rotate-90 w-full h-full" viewBox="0 0 100 100">
                  <circle cx="50" cy="50" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" className="text-gray-800/30" />
                  <circle cx="50" cy="50" r={radius} stroke="currentColor" strokeWidth="8" fill="transparent" strokeDasharray={circumference} strokeDashoffset={progressOffset} strokeLinecap="round" className={`transition-all duration-1000 ${timeLeft <= 10 ? 'text-red-500' : 'text-blue-400'}`} />
                </svg>
                <span className={`relative z-10 text-xl md:text-3xl font-black ${timeLeft <= 10 ? 'text-white' : 'text-blue-200'}`}>{timeLeft}</span>
              </div>
            ) : (
              <div className="bg-blue-900/30 border border-blue-400/30 rounded-full px-4 py-1.5 text-[10px] md:text-xs font-black text-blue-300 uppercase animate-pulse">
                {isHindi ? 'समय सीमा नहीं' : 'Free Thinking'}
              </div>
            )}
          </div>
        </header>

        <main className="flex-grow flex flex-col items-center justify-center px-2 md:px-4 pb-24 md:pb-0 overflow-y-auto">
          {loading ? (
            <div className="animate-scale-in flex flex-col items-center space-y-8">
              <div className="relative w-24 h-24">
                <div className="absolute inset-0 border-4 border-[#d4af37]/20 rounded-full"></div>
                <div className="absolute inset-0 border-4 border-t-[#d4af37] rounded-full animate-spin"></div>
              </div>
              <p className="gold-text text-xl md:text-2xl font-black uppercase tracking-widest text-center animate-pulse">
                {isHindi ? 'अगला प्रश्न तैयार हो रहा है...' : 'PREPARING QUESTION...'}
              </p>
            </div>
          ) : question ? (
            <div className="w-full max-w-5xl animate-fade-in relative">
              <QuizArea 
                question={question} 
                language={language} 
                hiddenOptions={hiddenOptions}
                isDoubleDipActive={isDoubleDipActive}
                showOptions={showOptions}
                isSpeaking={isSpeaking}
                onAnswer={handleAnswer} 
                onRepeat={() => {
                  if (question) startSpeechSequence(question, level, language, playerName);
                }}
              />
            </div>
          ) : null}
        </main>

        <footer className="fixed bottom-0 left-0 right-0 z-[100] md:hidden bg-black/80 backdrop-blur-xl border-t border-[#d4af37]/20">
           <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || status !== GameStatus.PLAYING} />
        </footer>
      </div>

      <aside className="hidden md:block w-72 lg:w-80 h-screen shadow-2xl relative z-40 border-l border-[#d4af37]/20">
        <Sidebar currentLevel={level} />
      </aside>

      {pollData && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/95 backdrop-blur-xl p-4 animate-fade-in">
          <div className="bg-[#000d1a] p-6 md:p-12 rounded-3xl gold-border max-w-lg w-full text-center animate-scale-in">
            <h3 className="gold-text text-2xl md:text-4xl font-black mb-8 uppercase italic">{isHindi ? 'ऑडियन्स पोल' : 'Audience Poll'}</h3>
            <div className="flex items-end justify-around h-48 md:h-64 mb-8 gap-4">
              {(Object.entries(pollData) as [string, number][]).map(([key, value]) => {
                const isHidden = hiddenOptions.includes(key);
                return (
                  <div key={key} className={`flex flex-col items-center w-full transition-opacity duration-500 ${isHidden ? 'opacity-10' : 'opacity-100'}`}>
                    <span className="text-white text-xs md:text-sm font-bold mb-2">{value}%</span>
                    <div className="relative w-full bg-blue-900/30 rounded-t-lg overflow-hidden border-x border-t border-white/10" style={{ height: `${value}%`, minHeight: value > 0 ? '5%' : '0%' }}>
                      <div className="absolute inset-0 bg-gradient-to-t from-blue-700 via-blue-400 to-cyan-300 animate-pulse"></div>
                    </div>
                    <div className={`w-full mt-2 font-black py-2 rounded-md text-sm ${isHidden ? 'bg-gray-800 text-gray-500' : 'bg-white text-black shadow-lg'}`}>
                      {key}
                    </div>
                  </div>
                );
              })}
            </div>
            <button onClick={() => setPollData(null)} className="bg-gradient-to-r from-[#d4af37] to-[#8a6d3b] text-black font-black py-4 px-16 rounded-full hover:scale-105 transition-all active:scale-95 shadow-[0_10px_30px_rgba(212,175,55,0.3)]">
              {isHindi ? 'आगे बढ़ें' : 'CONTINUE'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Modality } from "@google/genai";
import { Language, Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

let audioContext: AudioContext | null = null;
let currentSource: AudioBufferSourceNode | null = null;

const initAudioContext = () => {
  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  }
  return audioContext;
};

function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const stopSpeech = () => {
  if (currentSource) {
    try {
      currentSource.stop();
    } catch (e) {}
    currentSource = null;
  }
};

/**
 * Unified call for Question + Options reading to minimize latency.
 */
export const speakFullQuestionSequence = async (
  level: number, 
  question: Question, 
  lang: Language, 
  playerName: string
): Promise<boolean> => {
  stopSpeech();
  const ctx = initAudioContext();
  const isHindi = lang === Language.HINDI;

  // Construct a single optimized string for fast reading
  const text = isHindi 
    ? `${playerName} जी, सवाल ₹${level === 1 ? '5,000' : 'इतने'} के लिए: ${question.text}। विकल्प ए: ${question.options.A}। विकल्प बी: ${question.options.B}। विकल्प सी: ${question.options.C}। विकल्प डी: ${question.options.D}।`
    : `${playerName}, for level ${level}: ${question.text}. Option A: ${question.options.A}. Option B: ${question.options.B}. Option C: ${question.options.C}. Option D: ${question.options.D}.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' }, // Elderly Indian Male
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioBuffer = await decodeAudioData(
        decodeBase64(base64Audio),
        ctx,
        24000,
        1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
      currentSource = source;

      return new Promise((resolve) => {
        source.onended = () => {
          currentSource = null;
          resolve(true);
        };
      });
    }
  } catch (error) {
    console.error("TTS Pipeline Error:", error);
  }
  return false;
};

// Kept for backward compatibility but deprecated in favor of unified sequence
export const speakLifelineSuggestion = async (lang: Language) => {
  const ctx = initAudioContext();
  const isHindi = lang === Language.HINDI;
  const prompt = isHindi 
    ? "अगर आपको कठिनाई हो रही है, तो आप अपनी लाइफलाइन का उपयोग कर सकते हैं।" 
    : "If you're having difficulty, you may consider using a lifeline.";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' },
          },
        },
      },
    });
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), ctx, 24000, 1);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
    }
  } catch (e) {}
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import LanguageSelection from './components/LanguageSelection';
import NameInput from './components/NameInput';
import Disclaimer from './components/Disclaimer';
import Sidebar from './components/Sidebar';
import QuizArea from './components/QuizArea';
import Lifelines from './components/Lifelines';
import GameOver from './components/GameOver';
import { Language, GameStatus, Question, Lifelines as LifelinesType, PollData } from './types';
import { fetchQuestion } from './services/gemini';
import { getTimerForLevel, MONEY_TREE } from './constants';
import { 
  stopSpeech, 
  speakFullQuestionSequence,
  speakLifelineSuggestion 
} from './services/tts';

const App: React.FC = () => {
  const [status, setStatus] = useState<GameStatus>(GameStatus.NAME_INPUT);
  const [playerName, setPlayerName] = useState('');
  const [language, setLanguage] = useState<Language>(Language.ENGLISH);
  const [level, setLevel] = useState(1);
  const [question, setQuestion] = useState<Question | null>(null);
  const [loading, setLoading] = useState(false);
  const [timeLeft, setTimeLeft] = useState<number | null>(null);
  const [maxTime, setMaxTime] = useState<number | null>(null);
  const [hiddenOptions, setHiddenOptions] = useState<string[]>([]);
  const [pollData, setPollData] = useState<PollData | null>(null);
  const [isDoubleDipActive, setIsDoubleDipActive] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isVoiceEnabled, setIsVoiceEnabled] = useState(true);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [showOptions, setShowOptions] = useState(false);
  const [lifelineSuggested, setLifelineSuggested] = useState(false);
  const [canStartTimer, setCanStartTimer] = useState(false);
  const [lifelines, setLifelines] = useState<LifelinesType>({
    fiftyFifty: true,
    audiencePoll: true,
    doubleDip: true,
    flipQuestion: true
  });

  const timerRef = useRef<any>(null);

  const startUnifiedSpeech = useCallback(async (q: Question, l: number, lang: Language, name: string) => {
    setIsSpeaking(true);
    setShowOptions(true); // Reveal immediately as speech starts
    setCanStartTimer(false);

    // One single call for everything
    const speechFinished = await speakFullQuestionSequence(l, q, lang, name);

    setIsSpeaking(false);
    if (speechFinished) {
      setCanStartTimer(true); // Start timer only after host finishes reading
    }
  }, []);

  const loadQuestion = async (currLevel: number, lang: Language) => {
    stopSpeech();
    setIsSpeaking(false);
    setLoading(true);
    setShowOptions(false);
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);
    setIsSidebarOpen(false);
    setLifelineSuggested(false);
    setCanStartTimer(false);

    try {
      const q = await fetchQuestion(currLevel, lang);
      const initialTime = getTimerForLevel(currLevel);

      setQuestion(q);
      setMaxTime(initialTime);
      setTimeLeft(initialTime);

      setLoading(false);

      if (isVoiceEnabled) {
        // Execute immediately on load
        startUnifiedSpeech(q, currLevel, lang, playerName);
      } else {
        setShowOptions(true);
        setCanStartTimer(true);
      }
    } catch (error) {
      console.error("Failed to load question", error);
      setLoading(false);
    }
  };

  useEffect(() => {
    if (status === GameStatus.PLAYING && canStartTimer && timeLeft !== null && timeLeft > 0 && !loading) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev === null) return null;

          const timeElapsed = (maxTime || 0) - (prev - 1);
          const hasAvailableLifelines = Object.values(lifelines).some(v => v === true);

          if (timeElapsed >= 15 && !lifelineSuggested && hasAvailableLifelines && isVoiceEnabled && !isSpeaking) {
            setLifelineSuggested(true);
            speakLifelineSuggestion(language);
          }

          if (prev <= 1) {
            clearInterval(timerRef.current);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else if (status === GameStatus.PLAYING && timeLeft === 0 && canStartTimer && !loading) {
      handleAnswer(false, false);
    }

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [status, timeLeft, loading, lifelineSuggested, lifelines, language, isVoiceEnabled, isSpeaking, maxTime, canStartTimer]);

  const handleNameSubmit = (name: string) => {
    setPlayerName(name);
    setStatus(GameStatus.LANGUAGE_SELECT);
  };

  const handleLanguageSelect = (lang: Language) => {
    setLanguage(lang);
    setStatus(GameStatus.DISCLAIMER);
  };

  const handleStartGame = () => {
    setStatus(GameStatus.PLAYING);
    loadQuestion(1, language);
  };

  const handleAnswer = (isCorrect: boolean, isFirstAttemptOfDoubleDip: boolean) => {
    stopSpeech();
    setIsSpeaking(false);
    setCanStartTimer(false);
    if (isFirstAttemptOfDoubleDip) return;
    if (timerRef.current) clearInterval(timerRef.current);

    if (isCorrect) {
      setTimeout(() => {
        if (level === 15) {
          setStatus(GameStatus.WON);
        } else {
          const nextLevel = level + 1;
          setLevel(nextLevel);
          loadQuestion(nextLevel, language);
        }
      }, 2000);
    } else {
      setTimeout(() => {
        setStatus(GameStatus.LOST);
      }, 1500);
    }
  };

  const useLifeline = (type: keyof LifelinesType) => {
    if (!question || loading) return;
    stopSpeech();
    setIsSpeaking(false);

    setLifelines(prev => ({ ...prev, [type]: false }));

    if (type === 'fiftyFifty') {
      const incorrect = Object.keys(question.options).filter(k => k !== question.correctAnswer);
      const shuffled = incorrect.sort(() => 0.5 - Math.random());
      setHiddenOptions(shuffled.slice(0, 2));
    } else if (type === 'audiencePoll') {
      const correctKey = question.correctAnswer as keyof PollData;
      const data: PollData = { A: 0, B: 0, C: 0, D: 0 };
      const visibleKeys = (['A', 'B', 'C', 'D'] as (keyof PollData)[]).filter(k => !hiddenOptions.includes(k));
      const correctWeight = Math.floor(Math.random() * 20) + 65;
      data[correctKey] = correctWeight;
      let remainingPercent = 100 - correctWeight;
      const otherVisibleKeys = visibleKeys.filter(k => k !== correctKey);
      if (otherVisibleKeys.length > 0) {
        otherVisibleKeys.forEach((key, index) => {
          if (index === otherVisibleKeys.length - 1) {
            data[key] = remainingPercent;
          } else {
            const val = Math.floor(Math.random() * remainingPercent);
            data[key] = val;
            remainingPercent -= val;
          }
        });
      }
      setPollData(data);
    } else if (type === 'doubleDip') {
      setIsDoubleDipActive(true);
    } else if (type === 'flipQuestion') {
      loadQuestion(level, language);
    }
  };

  const restartGame = () => {
    stopSpeech();
    if (timerRef.current) clearInterval(timerRef.current);
    setLevel(1);
    setQuestion(null);
    setTimeLeft(null);
    setMaxTime(null);
    setLoading(false);
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);
    setIsSidebarOpen(false);
    setIsSpeaking(false);
    setShowOptions(false);
    setLifelineSuggested(false);
    setCanStartTimer(false);
    setStatus(GameStatus.NAME_INPUT);
    setLifelines({ fiftyFifty: true, audiencePoll: true, doubleDip: true, flipQuestion: true });
  };

  const isHindi = language === Language.HINDI;

  if (status === GameStatus.NAME_INPUT) {
    return <NameInput onNameSubmit={handleNameSubmit} />;
  }

  if (status === GameStatus.LANGUAGE_SELECT) {
    return <LanguageSelection onSelect={handleLanguageSelect} />;
  }

  if (status === GameStatus.WON || status === GameStatus.LOST) {
    return <GameOver isWon={status === GameStatus.WON} levelReached={level} language={language} onRestart={restartGame} />;
  }

  const currentLevelAmount = MONEY_TREE.find(l => l.id === level)?.amount || "₹0";
  const radius = 42;
  const circumference = 2 * Math.PI * radius;
  const progressOffset = timeLeft !== null && maxTime !== null ? circumference - (timeLeft / maxTime) * circumference : 0;

  return (
