import React, { useState, useEffect, useRef } from 'react';
import { Question, Language } from '../types';
import { recognizeVoiceAnswer } from '../services/gemini';

interface Props {
  question: Question;
  language: Language;
  hiddenOptions: string[];
  isDoubleDipActive: boolean;
  showOptions: boolean;
  isSpeaking: boolean;
  onAnswer: (correct: boolean, isFirstAttemptOfDoubleDip: boolean) => void;
  onRepeat: () => void;
}

const QuizArea: React.FC<Props> = ({ 
  question, language, hiddenOptions, isDoubleDipActive, showOptions, isSpeaking, onAnswer, onRepeat 
}) => {
  const [selected, setSelected] = useState<string | null>(null);
  const [locked, setLocked] = useState(false);
  const [showResult, setShowResult] = useState(false);
  const [failedOptions, setFailedOptions] = useState<string[]>([]);

  const [isRecording, setIsRecording] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    setSelected(null);
    setLocked(false);
    setShowResult(false);
    setFailedOptions([]);
  }, [question]);

  const handleOptionClick = (key: string) => {
    if (!locked && !showResult && !hiddenOptions.includes(key) && !failedOptions.includes(key)) {
      setSelected(key);
    }
  };

  const lockAnswer = () => {
    if (!selected) return;
    setLocked(true);

    setTimeout(() => {
      const isCorrect = selected === question.correctAnswer;
      setShowResult(true);

      if (isCorrect) {
        setTimeout(() => onAnswer(true, false), 2500);
      } else {
        if (isDoubleDipActive && failedOptions.length === 0) {
          setTimeout(() => {
            setFailedOptions(prev => [...prev, selected]);
            setSelected(null);
            setLocked(false);
            setShowResult(false);
            onAnswer(false, true);
          }, 1500);
        } else {
          setTimeout(() => onAnswer(false, false), 3500);
        }
      }
    }, 2000);
  };

  const startRecording = async () => {
    if (locked || showResult || isRecording || isTranscribing) return;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64String = (reader.result as string).split(',')[1];
          if (!base64String) return;

          setIsTranscribing(true);
          const recognizedOption = await recognizeVoiceAnswer(base64String, 'audio/webm', language);
          setIsTranscribing(false);

          if (recognizedOption && !hiddenOptions.includes(recognizedOption) && !failedOptions.includes(recognizedOption)) {
            setSelected(recognizedOption);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);

      setTimeout(() => {
        if (mediaRecorderRef.current?.state === 'recording') {
          stopRecording();
        }
      }, 3000);

    } catch (err) {
      console.error("Microphone access denied or error:", err);
      alert(language === Language.HINDI ? "माइक्रोफ़ोन एक्सेस की आवश्यकता है।" : "Microphone access is required.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const getOptionClass = (key: string) => {
    if (hiddenOptions.includes(key)) return 'opacity-0 pointer-events-none cursor-default';
    if (failedOptions.includes(key)) return 'opacity-40 grayscale cursor-not-allowed bg-red-950/20';

    if (showResult) {
      if (key === question.correctAnswer) {
        return 'option-correct scale-[1.05] z-10 shadow-[0_0_30px_#22c55e]';
      }
      if (key === selected && selected !== question.correctAnswer) {
        return 'option-wrong shadow-[0_0_30px_#ef4444] scale-[0.98]';
      }
      return 'opacity-20 grayscale-[0.9] blur-[1px]';
    }

    if (selected === key) {
      return locked 
        ? 'bg-gradient-to-r from-orange-600 to-yellow-500 border-white animate-pulse shadow-[0_0_25px_rgba(234,88,12,0.9)] scale-[1.03] z-10' 
        : 'bg-orange-500 border-white shadow-[0_0_15px_rgba(234,88,12,0.5)] scale-[1.02]';
    }

    return 'hover:bg-blue-900/40 border-[#d4af37]/40';
  };

  const isHindi = language === Language.HINDI;

  return (
    <div className="flex flex-col items-center justify-center p-2 md:p-8 space-y-4 md:space-y-6 w-full max-w-5xl mx-auto">

      {/* Host Avatar Section */}
      <div className="flex flex-col items-center mb-2 animate-fade-in">
        <div className={`relative w-20 h-20 md:w-28 md:h-28 rounded-full border-4 overflow-hidden bg-blue-900 transition-all duration-300 ${isSpeaking ? 'animate-speaking border-white scale-110 shadow-[0_0_50px_rgba(212,175,55,0.8)]' : 'border-[#d4af37] shadow-[0_0_20px_rgba(212,175,55,0.3)]'}`}>
          <img 
            src="https://api.dicebear.com/7.x/avataaars/svg?seed=Host&skinColor=ae5d29&topType=shortHair&hairColor=70b2d9&facialHairType=beardLight&facialHairColor=white" 
            alt="AI Host" 
            className="w-full h-full object-cover"
          />
          {isSpeaking && (
             <div className="absolute inset-0 bg-white/10 animate-pulse"></div>
          )}
        </div>
        <div className={`mt-2 px-4 py-0.5 rounded-full border transition-colors ${isSpeaking ? 'bg-white/20 border-white text-white font-black' : 'bg-black/60 border-[#d4af37]/40 gold-text font-bold'}`}>
           <span className="text-[10px] uppercase tracking-widest">{isHindi ? 'क्विज मास्टर' : 'QUIZ MASTER'} {isSpeaking && '• SPEAKING'}</span>
        </div>
      </div>

      {/* Question Box */}
      <div className="w-full p-6 md:p-12 bg-black/80 border-2 border-[#d4af37] rounded-2xl md:rounded-3xl text-center shadow-[0_0_40px_rgba(212,175,55,0.15)] relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#d4af37] to-transparent"></div>
        <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-[#001a33] px-6 py-0.5 border border-[#d4af37] rounded-full text-[10px] gold-text font-black uppercase tracking-[0.3em] whitespace-nowrap z-20">
          {isHindi ? 'प्रश्न' : 'Question'}
        </div>
        <h2 className="text-xl md:text-3xl lg:text-4xl font-bold text-white leading-tight md:leading-relaxed drop-shadow-lg relative z-10">
          {question.text}
        </h2>
      </div>

      {/* Voice & Replay Controls */}
      <div className="flex items-center justify-center space-x-6 md:space-x-12">
        <div className="flex flex-col items-center">
          <button
            onClick={isRecording ? stopRecording : startRecording}
            disabled={locked || showResult || isTranscribing}
            className={`relative group w-14 h-14 md:w-16 md:h-16 flex items-center justify-center rounded-full transition-all duration-300 border-2 ${
              isRecording 
                ? 'bg-red-500 border-white shadow-[0_0_20px_#ef4444] animate-mic-pulse' 
                : isTranscribing 
                  ? 'bg-blue-600 border-blue-400 animate-spin-slow shadow-[0_0_20px_#3b82f6]'
                  : 'bg-black/60 border-[#d4af37]/60 hover:border-[#d4af37] hover:scale-110 shadow-[0_0_15px_rgba(212,175,55,0.2)]'
            } ${locked || showResult ? 'opacity-20 cursor-not-allowed' : ''}`}
          >
            {isTranscribing ? <i className="fas fa-circle-notch animate-spin text-white"></i> : isRecording ? <i className="fas fa-stop text-white"></i> : <i className="fas fa-microphone gold-text group-hover:text-white"></i>}
          </button>
          <span className="text-[8px] md:text-[10px] gold-text font-bold uppercase tracking-widest mt-2">{isHindi ? 'उत्तर दें' : 'Answer'}</span>
        </div>

        <div className="flex flex-col items-center">
          <button
            onClick={onRepeat}
            disabled={locked || showResult || isSpeaking}
            className={`w-14 h-14 md:w-16 md:h-16 flex items-center justify-center rounded-full border-2 border-[#d4af37]/60 bg-black/60 transition-all hover:scale-110 hover:border-[#d4af37] ${isSpeaking || locked || showResult ? 'opacity-20 cursor-not-allowed' : ''}`}
          >
            <i className="fas fa-redo gold-text"></i>
          </button>
          <span className="text-[8px] md:text-[10px] gold-text font-bold uppercase tracking-widest mt-2">{isHindi ? 'फिर से सुनें' : 'Repeat'}</span>
        </div>
      </div>

      {/* Options Grid */}
      <div className={`grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6 w-full px-2 max-w-4xl transition-all duration-500 ${showOptions ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-10 scale-95 pointer-events-none'}`}>
        {Object.entries(question.options).map(([key, value]) => (
          <button
            key={key}
            onClick={() => handleOptionClick(key)}
            disabled={locked || showResult || hiddenOptions.includes(key) || failedOptions.includes(key)}
            className={`option-button group flex items-center px-8 md:px-12 py-4 md:py-6 text-white text-base md:text-xl font-bold min-h-[60px] md:min-h-[80px] transition-all duration-300 ${getOptionClass(key)}`}
          >
            <span className={`mr-4 md:mr-6 font-black text-xl md:text-2xl transition-colors duration-300 ${selected === key || (showResult && (key === selected || key === question.correctAnswer)) ? 'text-white' : 'gold-text'}`}>
              {key}:
            </span>
            <span className="text-left leading-tight line-clamp-2 md:line-clamp-3 flex-grow">{value}</span>
          </button>
        ))}
      </div>

      {/* Action Area */}
      <div className="h-20 md:h-24 flex items-center justify-center w-full">
        {selected && !locked && !showResult && (
          <button
            onClick={lockAnswer}
            className="group relative bg-gradient-to-r from-orange-600 via-orange-500 to-orange-400 text-white font-black py-4 px-14 md:px-24 rounded-full text-xl md:text-3xl shadow-[0_15px_40px_rgba(234,88,12,0.4)] transition-all transform hover:scale-110 active:scale-95 animate-bounce uppercase tracking-tighter overflow-hidden"
          >
            <span className="relative z-10">{isHindi ? 'लॉक किया जाए!' : 'Lock Kiya Jaye!'}</span>
            <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700 skew-x-12"></div>
          </button>
        )}
        {locked && !showResult && (
          <div className="flex flex-col items-center">
            <div className="text-orange-400 font-black text-2xl md:text-4xl animate-pulse uppercase italic tracking-[0.2em]">
              {isHindi ? 'चेक कर रहे हैं...' : 'Checking...'}
            </div>
          </div>
        )}
        {showResult && (
          <div className={`font-black text-3xl md:text-5xl animate-scale-in uppercase tracking-tighter drop-shadow-2xl text-center ${selected === question.correctAnswer ? 'text-green-400' : 'text-red-500'}`}>
            {selected === question.correctAnswer ? (isHindi ? 'सही जवाब!' : 'Correct!') : (isHindi ? 'गलत जवाब!' : 'Wrong!')}
          </div>
        )}
      </div>

      {/* Explanation Box */}
      {showResult && (
        <div className="w-full max-w-3xl p-5 md:p-6 bg-black/60 border-l-4 border-[#d4af37] rounded-xl text-white animate-fade-in backdrop-blur-xl shadow-2xl">
          <p className="text-sm md:text-lg leading-relaxed italic text-blue-50">"{question.explanation}"</p>
        </div>
      )}
    </div>
  );
};

