          ) : question ? (
            <div className="w-full max-w-5xl animate-fade-in relative">
              <QuizArea 
                question={question} language={language} hiddenOptions={hiddenOptions} isDoubleDipActive={isDoubleDipActive} showOptions={showOptions} isSpeaking={isSpeaking} onAnswer={handleAnswer} 
                onRepeat={() => { if (question) startUnifiedSpeech(question, level, language, playerName); }}
