        <footer className="fixed bottom-0 left-0 right-0 z-[100] md:hidden bg-black/80 backdrop-blur-xl border-t border-[#d4af37]/20"><Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || status !== GameStatus.PLAYING} /></footer>
