import { GoogleGenAI, Modality } from "@google/genai";
import { Language, Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

let audioContext: AudioContext | null = null;
let currentSource: AudioBufferSourceNode | null = null;

const initAudioContext = () => {
  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  }
  return audioContext;
};

function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const stopSpeech = () => {
  if (currentSource) {
    try {
      currentSource.stop();
    } catch (e) {}
    currentSource = null;
  }
};

/**
 * ULTRA-LOW LATENCY: Fetches question and options audio in one stream.
 * Predicts timings to reveal options one-by-one.
 */
export const speakFullQuestionSequence = async (
  level: number,
  question: Question,
  lang: Language,
  onOptionReveal: (key: string) => void
): Promise<void> => {
  stopSpeech();
  const ctx = initAudioContext();
  const isHindi = lang === Language.HINDI;

  // STRICT DIRECT READ: No intro, no thinking.
  const text = isHindi
    ? `${question.text}। विकल्प A: ${question.options.A}। विकल्प B: ${question.options.B}। विकल्प C: ${question.options.C}। विकल्प D: ${question.options.D}।`
    : `${question.text}. Option A: ${question.options.A}. Option B: ${question.options.B}. Option C: ${question.options.C}. Option D: ${question.options.D}.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' }, // Experienced Indian Male
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), ctx, 24000, 1);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
      currentSource = source;

      // REVEAL LOGIC: 
      // We estimate timings based on text length to sync UI with Voice
      const fullText = text;
      const qPart = isHindi ? question.text : question.text;
      const qRatio = qPart.length / fullText.length;
      const qDuration = audioBuffer.duration * qRatio;
      const remaining = audioBuffer.duration - qDuration;
      const optDuration = remaining / 4;

      // Reveal Question instantly
      setTimeout(() => onOptionReveal('A'), qDuration * 1000);
      setTimeout(() => onOptionReveal('B'), (qDuration + optDuration) * 1000);
      setTimeout(() => onOptionReveal('C'), (qDuration + optDuration * 2) * 1000);
      setTimeout(() => onOptionReveal('D'), (qDuration + optDuration * 3) * 1000);

      return new Promise((resolve) => {
        source.onended = () => {
          currentSource = null;
          resolve();
        };
      });
    }
  } catch (error) {
    console.error("TTS Pipeline Error:", error);
    // Failsafe: reveal all options immediately
    onOptionReveal('A'); onOptionReveal('B'); onOptionReveal('C'); onOptionReveal('D');
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Language, Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Existing categories...
const CATEGORIES = ["Indian Freedom Struggle", "Ancient Indian Science & Medicine", "World Exploration & Voyagers", "Nobel Prizes & Global Awards", "Indian Railways & Infrastructure", "Wildlife & Endangered Species", "Nuclear & Space Programs of India", "Classical Arts & Dance Forms", "Global Economic History", "Inventions & Their Inventors", "Indian Judicial System & Landmarks", "Famous Speeches in History", "Olympic Games Records", "Traditional Cuisines & Origins", "Modern Tech (AI, Quantum, Robotics)", "Geopolitics & UN History", "Flora of the Indian Subcontinent", "Obscure Literary Works", "Indian Cinema's Golden Era", "Architecture of Medieval India"];

export const fetchQuestion = async (level: number, lang: Language, attempt = 0): Promise<Question> => {
  const modelName = level === 15 ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
  const difficultyTier = level > 13 ? "expert" : level > 9 ? "high" : level > 4 ? "mid" : "low";
  const languageName = lang === Language.HINDI ? "Hindi" : "English";
  const category = CATEGORIES[Math.floor(Math.random() * CATEGORIES.length)];

  const prompt = `Act as an expert KBC quiz master. Create one unique, factually accurate multiple-choice question.
  CATEGORY: ${category}
  LEVEL: ${level}/15
  LANGUAGE: ${languageName}
  Respond with a SINGLE JSON OBJECT ONLY.`;

  try {
    const config: any = {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          text: { type: Type.STRING },
          options: {
            type: Type.OBJECT,
            properties: { A: { type: Type.STRING }, B: { type: Type.STRING }, C: { type: Type.STRING }, D: { type: Type.STRING } },
            required: ["A", "B", "C", "D"]
          },
          correctAnswer: { type: Type.STRING, enum: ["A", "B", "C", "D"] },
          explanation: { type: Type.STRING }
        },
        required: ["text", "options", "correctAnswer", "explanation"]
      }
    };
    if (level >= 10) config.thinkingConfig = { thinkingBudget: 2000 };

    const response = await ai.models.generateContent({ model: modelName, contents: prompt, config });
    return JSON.parse(response.text || "{}") as Question;
  } catch (error) {
    if (attempt < 2) return fetchQuestion(level, lang, attempt + 1);
    throw error;
  }
};

/**
 * INTENT RECOGNITION: Maps audio to structured JSON commands.
 * Commands: SELECT_OPTION, LOCK_OPTION, USE_LIFELINE, QUIT_GAME
 */
export const recognizeVoiceCommand = async (base64Audio: string, mimeType: string, lang: Language): Promise<any | null> => {
  const prompt = `You are a KBC Command Intent Recognizer. Analyze the audio for these specific intents ONLY:
  1. SELECT_OPTION: user says "Option A", "बी", "विकल्प सी"
  2. LOCK_OPTION: user says "Option B lock कीजिए", "ए लॉक करो", "Lock Option D"
  3. USE_LIFELINE: user says "Audience poll", "50-50", "फिफ्टी फिफ्टी", "Flip question"
  4. QUIT_GAME: user says "Quit game", "खेल छोड़ना है", "Exit"

  Rules:
  - If background noise or unclear, return {"intent": "NONE"}.
  - Output VALID JSON ONLY.
  - Return characters A, B, C, D for options.
  - Lifeline keys: 'audiencePoll', 'fiftyFifty', 'doubleDip', 'flipQuestion'

  Example Response: {"intent": "LOCK_OPTION", "target": "B"}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        { inlineData: { data: base64Audio, mimeType: mimeType } },
        { text: prompt }
      ],
      config: { 
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 0 } 
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Intent Recognition Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Question, Language } from '../types';
import { recognizeVoiceCommand } from '../services/gemini';

interface Props {
  question: Question;
  language: Language;
  hiddenOptions: string[];
  isDoubleDipActive: boolean;
  visibleOptions: string[];
  isSpeaking: boolean;
  onAnswer: (correct: boolean, isFirstAttemptOfDoubleDip: boolean) => void;
  onRepeat: () => void;
  onVoiceCommand: (intentData: any) => void;
}

const QuizArea: React.FC<Props> = ({ 
  question, language, hiddenOptions, isDoubleDipActive, visibleOptions, isSpeaking, onAnswer, onRepeat, onVoiceCommand 
}) => {
  const [selected, setSelected] = useState<string | null>(null);
  const [locked, setLocked] = useState(false);
  const [showResult, setShowResult] = useState(false);
  const [failedOptions, setFailedOptions] = useState<string[]>([]);

  const [isRecording, setIsRecording] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    setSelected(null);
    setLocked(false);
    setShowResult(false);
    setFailedOptions([]);
  }, [question]);

  // Sync selection with state (for voice commands coming from parent)
  useEffect(() => {
    // If parent forces a selection via state (handled in App.tsx)
  }, []);

  const handleOptionClick = (key: string) => {
    if (!locked && !showResult && !hiddenOptions.includes(key) && !failedOptions.includes(key)) {
      setSelected(key);
    }
  };

  const lockAnswer = (key?: string) => {
    const target = key || selected;
    if (!target) return;

    setSelected(target);
    setLocked(true);

    setTimeout(() => {
      const isCorrect = target === question.correctAnswer;
      setShowResult(true);

      if (isCorrect) {
        setTimeout(() => onAnswer(true, false), 2500);
      } else {
        if (isDoubleDipActive && failedOptions.length === 0) {
          setTimeout(() => {
            setFailedOptions(prev => [...prev, target]);
            setSelected(null);
            setLocked(false);
            setShowResult(false);
            onAnswer(false, true);
          }, 1500);
        } else {
          setTimeout(() => onAnswer(false, false), 3500);
        }
      }
    }, 2000);
  };

  const startRecording = async () => {
    if (locked || showResult || isRecording || isTranscribing) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (e) => e.data.size > 0 && audioChunksRef.current.push(e.data);
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64String = (reader.result as string).split(',')[1];
          if (!base64String) return;
          setIsTranscribing(true);
          const command = await recognizeVoiceCommand(base64String, 'audio/webm', language);
          setIsTranscribing(false);
          if (command && command.intent !== 'NONE') {
            if (command.intent === 'SELECT_OPTION') setSelected(command.target);
            if (command.intent === 'LOCK_OPTION') lockAnswer(command.target);
            onVoiceCommand(command);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
      setTimeout(() => stopRecording(), 3000);
    } catch (err) { console.error(err); }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current?.state === 'recording') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const getOptionClass = (key: string) => {
    if (hiddenOptions.includes(key)) return 'opacity-0 pointer-events-none';
    if (failedOptions.includes(key)) return 'opacity-40 grayscale bg-red-950/20';
    if (showResult) {
      if (key === question.correctAnswer) return 'option-correct scale-105 z-10';
      if (key === selected) return 'option-wrong';
      return 'opacity-20 grayscale blur-[1px]';
    }
    if (selected === key) return locked ? 'option-selected animate-pulse scale-105' : 'option-selected';
    return 'hover:bg-blue-900/40 border-[#d4af37]/40';
  };

  const isHindi = language === Language.HINDI;

  return (
    <div className="flex flex-col items-center justify-center p-2 md:p-8 space-y-6 w-full max-w-5xl mx-auto">
      <div className="flex flex-col items-center mb-2 animate-fade-in">
        <div className={`relative w-24 h-24 md:w-32 md:h-32 rounded-full border-4 overflow-hidden transition-all duration-300 ${isSpeaking ? 'animate-speaking border-white scale-110' : 'border-[#d4af37]'}`}>
          <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Host&skinColor=ae5d29&topType=shortHair&hairColor=70b2d9&facialHairType=beardLight" alt="Host" className="w-full h-full object-cover" />
        </div>
      </div>

      <div className="w-full p-6 md:p-12 bg-black/80 border-2 border-[#d4af37] rounded-3xl text-center shadow-2xl relative overflow-hidden">
        <h2 className="text-xl md:text-3xl lg:text-4xl font-bold text-white leading-relaxed">{question.text}</h2>
      </div>

      <div className="flex items-center justify-center space-x-12">
        <button onClick={isRecording ? stopRecording : startRecording} disabled={locked || showResult} className={`w-16 h-16 flex items-center justify-center rounded-full border-2 ${isRecording ? 'bg-red-500 animate-mic-pulse' : 'bg-black/60 border-[#d4af37]/60'}`}>
          <i className={`fas ${isTranscribing ? 'fa-circle-notch fa-spin' : isRecording ? 'fa-stop' : 'fa-microphone'} text-white`}></i>
        </button>
        <button onClick={onRepeat} disabled={locked || showResult || isSpeaking} className="w-16 h-16 flex items-center justify-center rounded-full border-2 border-[#d4af37]/60 bg-black/60"><i className="fas fa-redo gold-text"></i></button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6 w-full max-w-4xl">
        {Object.entries(question.options).map(([key, value]) => (
          <button
            key={key}
            onClick={() => handleOptionClick(key)}
            disabled={locked || showResult || !visibleOptions.includes(key)}
            className={`option-button flex items-center px-8 py-5 text-white text-lg md:text-xl font-bold transition-all duration-500 ${!visibleOptions.includes(key) ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'} ${getOptionClass(key)}`}
          >
            <span className="mr-6 gold-text text-2xl">{key}:</span>
            <span className="text-left">{value}</span>
          </button>
        ))}
      </div>

      <div className="h-24 flex items-center justify-center">
        {selected && !locked && !showResult && (
          <button onClick={() => lockAnswer()} className="bg-gradient-to-r from-orange-600 to-orange-400 text-white font-black py-4 px-20 rounded-full text-2xl shadow-2xl animate-bounce uppercase tracking-widest">
            {isHindi ? 'लॉक करें!' : 'Lock It!'}
          </button>
        )}
      </div>
    </div>
  );
};

export default QuizArea;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import LanguageSelection from './components/LanguageSelection';
import NameInput from './components/NameInput';
import Disclaimer from './components/Disclaimer';
import Sidebar from './components/Sidebar';
import QuizArea from './components/QuizArea';
import Lifelines from './components/Lifelines';
import GameOver from './components/GameOver';
import { Language, GameStatus, Question, Lifelines as LifelinesType, PollData } from './types';
import { fetchQuestion } from './services/gemini';
import { getTimerForLevel, MONEY_TREE } from './constants';
import { stopSpeech, speakFullQuestionSequence } from './services/tts';

const App: React.FC = () => {
  const [status, setStatus] = useState<GameStatus>(GameStatus.NAME_INPUT);
  const [playerName, setPlayerName] = useState('');
  const [language, setLanguage] = useState<Language>(Language.ENGLISH);
  const [level, setLevel] = useState(1);
  const [question, setQuestion] = useState<Question | null>(null);
  const [loading, setLoading] = useState(false);
  const [timeLeft, setTimeLeft] = useState<number | null>(null);
  const [maxTime, setMaxTime] = useState<number | null>(null);
  const [hiddenOptions, setHiddenOptions] = useState<string[]>([]);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);
  const [pollData, setPollData] = useState<PollData | null>(null);
  const [isDoubleDipActive, setIsDoubleDipActive] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isVoiceEnabled, setIsVoiceEnabled] = useState(true);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [showQuitConfirm, setShowQuitConfirm] = useState(false);
  const [canStartTimer, setCanStartTimer] = useState(false);
  const [lifelines, setLifelines] = useState<LifelinesType>({
    fiftyFifty: true, audiencePoll: true, doubleDip: true, flipQuestion: true
  });

  const timerRef = useRef<any>(null);

  const startUnifiedSpeech = useCallback(async (q: Question, l: number, lang: Language, name: string) => {
    setIsSpeaking(true);
    setVisibleOptions([]); 
    setCanStartTimer(false);

    await speakFullQuestionSequence(l, q, lang, (key) => {
      setVisibleOptions(prev => [...new Set([...prev, key])]);
    });

    setIsSpeaking(false);
    setCanStartTimer(true); 
  }, []);

  const loadQuestion = async (currLevel: number, lang: Language) => {
    stopSpeech();
    setLoading(true);
    setVisibleOptions([]);
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);
    setCanStartTimer(false);

    try {
      const q = await fetchQuestion(currLevel, lang);
      setQuestion(q);
      const initialTime = getTimerForLevel(currLevel);
      setMaxTime(initialTime);
      setTimeLeft(initialTime);
      setLoading(false);

      if (isVoiceEnabled) {
        startUnifiedSpeech(q, currLevel, lang, playerName);
      } else {
        setVisibleOptions(['A', 'B', 'C', 'D']);
        setCanStartTimer(true);
      }
    } catch (error) { setLoading(false); }
  };

  useEffect(() => {
    if (status === GameStatus.PLAYING && canStartTimer && timeLeft !== null && timeLeft > 0 && !loading) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev === null || prev <= 1) { clearInterval(timerRef.current); return 0; }
          return prev - 1;
        });
      }, 1000);
    } else if (status === GameStatus.PLAYING && timeLeft === 0 && canStartTimer) {
      handleAnswer(false, false);
    }
    return () => clearInterval(timerRef.current);
  }, [status, timeLeft, loading, canStartTimer]);

  const handleVoiceCommand = (intentData: any) => {
    if (intentData.intent === 'USE_LIFELINE') useLifeline(intentData.target);
    if (intentData.intent === 'QUIT_GAME') setShowQuitConfirm(true);
  };

  const handleAnswer = (isCorrect: boolean, isFirstAttemptOfDoubleDip: boolean) => {
    stopSpeech();
    if (isFirstAttemptOfDoubleDip) return;
    clearInterval(timerRef.current);
    if (isCorrect) {
      setTimeout(() => {
        if (level === 15) setStatus(GameStatus.WON);
        else { setLevel(l => l + 1); loadQuestion(level + 1, language); }
      }, 2000);
    } else {
      setTimeout(() => setStatus(GameStatus.LOST), 1500);
    }
  };

  const useLifeline = (type: keyof LifelinesType) => {
    if (!question || loading) return;
    setLifelines(prev => ({ ...prev, [type]: false }));
    if (type === 'fiftyFifty') {
      const incorrect = Object.keys(question.options).filter(k => k !== question.correctAnswer).sort(() => 0.5 - Math.random());
      setHiddenOptions(incorrect.slice(0, 2));
    } else if (type === 'doubleDip') setIsDoubleDipActive(true);
    else if (type === 'flipQuestion') loadQuestion(level, language);
    // Poll handling...
  };

  const handleQuit = () => { stopSpeech(); setStatus(GameStatus.LOST); setShowQuitConfirm(false); };

  const isHindi = language === Language.HINDI;

  if (status === GameStatus.NAME_INPUT) return <NameInput onNameSubmit={(n) => { setPlayerName(n); setStatus(GameStatus.LANGUAGE_SELECT); }} />;
  if (status === GameStatus.LANGUAGE_SELECT) return <LanguageSelection onSelect={(l) => { setLanguage(l); setStatus(GameStatus.DISCLAIMER); }} />;
  if (status === GameStatus.WON || status === GameStatus.LOST) return <GameOver isWon={status === GameStatus.WON} levelReached={level} language={language} onRestart={() => window.location.reload()} />;

  return (
    <div className="min-h-screen kbc-bg flex flex-col md:flex-row relative text-white">
      {status === GameStatus.DISCLAIMER && <Disclaimer language={language} onStart={() => { setStatus(GameStatus.PLAYING); loadQuestion(1, language); }} />}

      {showQuitConfirm && (
        <div className="fixed inset-0 z-[300] bg-black/90 flex items-center justify-center p-6 backdrop-blur-md">
          <div className="bg-[#001a33] p-10 rounded-3xl gold-border max-w-md w-full text-center space-y-8 animate-scale-in">
            <h2 className="text-3xl font-black gold-text uppercase italic">{isHindi ? 'खेल छोड़ना?' : 'Quit Game?'}</h2>
            <p className="text-xl">{isHindi ? 'क्या आप वाकई खेल छोड़ना चाहते हैं?' : 'Are you sure you want to leave the game?'}</p>
            <div className="flex gap-4">
              <button onClick={handleQuit} className="flex-1 bg-red-600 text-white font-bold py-4 rounded-xl uppercase">Yes, Quit</button>
              <button onClick={() => setShowQuitConfirm(false)} className="flex-1 bg-green-600 text-white font-bold py-4 rounded-xl uppercase">Stay</button>
            </div>
          </div>
        </div>
      )}

      <div className="flex-grow flex flex-col relative min-h-screen z-10">
        <header className="w-full flex justify-between items-center px-6 py-4 bg-black/60 border-b border-[#d4af37]/30 backdrop-blur-md sticky top-0 z-[50]">
          <div className="flex items-center space-x-4">
            <button onClick={() => setShowQuitConfirm(true)} className="bg-red-900/40 border border-red-500/40 text-red-200 px-4 py-1.5 rounded-full text-xs font-black uppercase hover:bg-red-600 transition-colors">Quit</button>
            <div className="flex flex-col">
              <span className="text-gray-400 font-bold uppercase text-[10px] tracking-widest">{playerName} • LVL {level}</span>
              <span className="gold-text font-black text-xl leading-none">{MONEY_TREE.find(l => l.id === level)?.amount}</span>
            </div>
          </div>
          <div className="flex items-center space-x-6">
            <button onClick={() => setIsVoiceEnabled(!isVoiceEnabled)} className={`w-12 h-12 rounded-full flex items-center justify-center ${isVoiceEnabled ? 'bg-[#d4af37] text-black' : 'bg-gray-800 text-gray-400'}`}><i className={`fas ${isVoiceEnabled ? 'fa-volume-up' : 'fa-volume-mute'}`}></i></button>
            <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading} />
            <div className={`relative w-16 h-16 flex items-center justify-center rounded-full ${timeLeft && timeLeft <= 10 ? 'animate-timer-critical' : 'animate-timer-pulse'}`}>
               <span className="text-2xl font-black">{timeLeft ?? '∞'}</span>
            </div>
          </div>
        </header>

        <main className="flex-grow flex flex-col items-center justify-center p-4">
          {loading ? (
            <div className="flex flex-col items-center space-y-6"><div className="w-16 h-16 border-4 border-t-[#d4af37] border-white/10 rounded-full animate-spin"></div><p className="gold-text font-black uppercase tracking-widest">Loading Hot Seat...</p></div>
          ) : question ? (
            <QuizArea 
              question={question} language={language} hiddenOptions={hiddenOptions} isDoubleDipActive={isDoubleDipActive} 
              visibleOptions={visibleOptions} isSpeaking={isSpeaking} onAnswer={handleAnswer} 
              onRepeat={() => startUnifiedSpeech(question, level, language, playerName)}
              onVoiceCommand={handleVoiceCommand}
            />
          ) : null}
        </main>
      </div>
      <aside className="hidden lg:block w-80 h-screen border-l border-[#d4af37]/20"><Sidebar currentLevel={level} /></aside>
    </div>
  );
};

export default App;

