      {status === GameStatus.DISCLAIMER && <Disclaimer language={language} onStart={() => { setStatus(GameStatus.PLAYING); loadQuestion(1, language); }} />}

      {showQuitConfirm && (
        <div className="fixed inset-0 z-[300] bg-black/95 flex items-center justify-center p-6 backdrop-blur-xl">
          <div className="bg-[#001a33] p-10 rounded-3xl gold-border max-w-md w-full text-center space-y-8 animate-scale-in">
            <h2 className="text-3xl font-black gold-text uppercase italic">{isHindi ? 'खेल छोड़ना?' : 'Quit Game?'}</h2>
            <p className="text-xl text-blue-100">{isHindi ? 'क्या आप वाकई खेल छोड़ना चाहते हैं?' : 'Are you sure you want to leave the game?'}</p>
            <div className="flex gap-4">
              <button onClick={handleQuit} className="flex-1 bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-xl uppercase transition-colors shadow-lg shadow-red-900/40">Yes, Quit</button>
              <button onClick={() => setShowQuitConfirm(false)} className="flex-1 bg-green-600 hover:bg-green-700 text-white font-bold py-4 rounded-xl uppercase transition-colors shadow-lg shadow-green-900/40">Stay</button>
            </div>
          </div>
        </div>
      )}

      {/* Main Content Area */}
      <div className="flex-grow flex flex-col relative min-h-screen z-10">
        <header className="w-full flex justify-between items-center px-6 py-4 bg-black/60 border-b border-[#d4af37]/30 backdrop-blur-md sticky top-0 z-[50]">
          <div className="flex items-center space-x-4">
            <button 
              onClick={() => setShowQuitConfirm(true)} 
              className="bg-red-900/60 border border-red-500/60 text-white px-5 py-2 rounded-full text-xs font-black uppercase hover:bg-red-600 transition-all shadow-[0_0_15px_rgba(239,68,68,0.3)]"
            >
              QUIT
            </button>
            <div className="flex flex-col">
              <span className="text-gray-400 font-bold uppercase text-[10px] tracking-widest">{playerName} • LVL {level}</span>
              <span className="gold-text font-black text-xl leading-none">{currentLevelAmount}</span>
            </div>
          </div>

          <div className="flex items-center space-x-4 md:space-x-8">
            <button 
              onClick={() => setIsVoiceEnabled(!isVoiceEnabled)} 
              className={`w-12 h-12 rounded-full flex items-center justify-center border transition-all ${isVoiceEnabled ? 'bg-[#d4af37] text-black border-white shadow-[0_0_15px_rgba(212,175,55,0.5)]' : 'bg-gray-800 text-gray-400 border-gray-700'}`}
              title={isHindi ? 'आवाज मोड' : 'Voice Mode'}
            >
              <i className={`fas ${isVoiceEnabled ? 'fa-volume-up' : 'fa-volume-mute'} text-lg`}></i>
            </button>

            <div className={`relative w-14 h-14 md:w-16 md:h-16 flex items-center justify-center rounded-full border-2 ${timeLeft && timeLeft <= 10 ? 'animate-timer-critical border-red-500' : 'animate-timer-pulse border-blue-400'}`}>
               <span className={`text-xl md:text-2xl font-black ${timeLeft && timeLeft <= 10 ? 'text-red-200' : 'text-blue-100'}`}>{timeLeft ?? '∞'}</span>
            </div>
          </div>
        </header>

        <main className="flex-grow flex flex-col items-center justify-start p-4 md:p-8 overflow-y-auto space-y-6">
          {loading ? (
            <div className="flex flex-col items-center justify-center flex-grow space-y-8">
              <div className="w-20 h-20 border-4 border-t-[#d4af37] border-white/10 rounded-full animate-spin shadow-[0_0_30px_rgba(212,175,55,0.2)]"></div>
              <p className="gold-text text-2xl font-black uppercase tracking-[0.3em] animate-pulse">{isHindi ? 'हॉट सीट पर स्वागत है...' : 'LOADING HOT SEAT...'}</p>
            </div>
          ) : question ? (
            <div className="w-full flex flex-col items-center space-y-8 animate-fade-in">
              {/* Central Dashboard for Lifelines (Clearly Visible Below Host/Above Question) */}
              <div className="w-full max-w-4xl order-2 md:order-1">
                <div className="mb-2 text-center">
                   <span className="text-[10px] gold-text font-black uppercase tracking-[0.2em]">{isHindi ? 'लाइफलाइन पैनल' : 'LIFELINE PANEL'}</span>
                </div>
                <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || isSpeaking} />
              </div>

              {/* Quiz Area */}
              <div className="w-full order-1 md:order-2">
                <QuizArea 
                  question={question} 
                  language={language} 
                  hiddenOptions={hiddenOptions} 
                  isDoubleDipActive={isDoubleDipActive} 
                  visibleOptions={visibleOptions} 
                  isSpeaking={isSpeaking} 
                  onAnswer={handleAnswer} 
                  onRepeat={() => startUnifiedSpeech(question, level, language, playerName)}
                  onVoiceCommand={handleVoiceCommand}
                />
              </div>
            </div>
          ) : null}
        </main>
      </div>

      {/* Sidebar for Desktop */}
      <aside className="hidden lg:block w-80 h-screen border-l border-[#d4af37]/20 sticky top-0">
        <Sidebar currentLevel={level} />
      </aside>

      {/* Audience Poll Modal */}
      {pollData && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-6 animate-fade-in">
          <div className="bg-[#000d1a] p-8 md:p-12 rounded-3xl gold-border max-w-lg w-full text-center space-y-8 animate-scale-in">
            <h3 className="gold-text text-3xl font-black uppercase italic tracking-widest">{isHindi ? 'ऑडियन्स पोल' : 'Audience Poll'}</h3>
            <div className="flex items-end justify-around h-64 gap-4">
              {Object.entries(pollData).map(([key, value]) => (
                <div key={key} className="flex flex-col items-center w-full">
                  <span className="text-blue-100 text-sm font-bold mb-2">{value}%</span>
                  <div className="relative w-full bg-blue-900/40 rounded-t-lg border border-white/10 overflow-hidden" style={{ height: `${value}%` }}>
                    <div className="absolute inset-0 bg-gradient-to-t from-blue-700 to-cyan-400 animate-pulse"></div>
                  </div>
                  <div className="w-full mt-3 bg-white text-black font-black py-2 rounded-lg text-lg shadow-lg">{key}</div>
                </div>
              ))}
            </div>
            <button 
              onClick={() => setPollData(null)} 
              className="bg-gradient-to-r from-[#d4af37] to-[#8a6d3b] text-black font-black py-4 px-16 rounded-full hover:scale-105 transition-all shadow-xl shadow-gold/20 uppercase"
            >
              {isHindi ? 'आगे बढ़ें' : 'CONTINUE'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Lifelines as LifelinesType } from '../types';

interface Props {
  lifelines: LifelinesType;
  onUse: (type: keyof LifelinesType) => void;
  disabled: boolean;
}

const Lifelines: React.FC<Props> = ({ lifelines, onUse, disabled }) => {
  const items = [
    { key: 'fiftyFifty' as keyof LifelinesType, label: '50:50', icon: 'fa-adjust' },
    { key: 'audiencePoll' as keyof LifelinesType, label: 'Audience Poll', icon: 'fa-users' },
    { key: 'doubleDip' as keyof LifelinesType, label: 'Double Dip', icon: 'fa-repeat' },
    { key: 'flipQuestion' as keyof LifelinesType, label: 'Flip', icon: 'fa-shuffle' },
  ];

  return (
    <div className="flex justify-center items-center gap-2 md:gap-4 w-full max-w-2xl mx-auto py-2 px-4 bg-gradient-to-r from-transparent via-blue-900/40 to-transparent rounded-full border-y border-[#d4af37]/20 backdrop-blur-md">
      {items.map((item) => (
        <button
          key={item.key}
          onClick={() => onUse(item.key)}
          disabled={disabled || !lifelines[item.key]}
          className={`group relative flex items-center justify-center w-12 h-12 md:w-20 md:h-20 rounded-full border-2 transition-all duration-300 ${
            !lifelines[item.key] 
              ? 'opacity-20 bg-gray-950 border-gray-800 cursor-not-allowed' 
              : 'bg-black/60 border-[#d4af37]/60 hover:border-white hover:scale-110 shadow-[0_0_15px_rgba(212,175,55,0.2)]'
          }`}
          title={item.label}
        >
          {lifelines[item.key] && (
            <div className="absolute top-0 right-0 w-3 h-3 bg-green-500 rounded-full border border-white animate-pulse"></div>
          )}
          <i className={`fas ${item.icon} text-sm md:text-2xl ${!lifelines[item.key] ? 'text-gray-600' : 'gold-text group-hover:text-white'}`}></i>

          <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-opacity bg-black/90 border border-[#d4af37] px-2 py-0.5 rounded text-[8px] gold-text font-black whitespace-nowrap pointer-events-none z-50">
            {item.label}
          </div>
        </button>
      ))}
    </div>
  );
};

export default Lifelines;

