import React, { useState, useEffect, useRef } from 'react';
import { Question, Language } from '../types';
import { recognizeVoiceCommand } from '../services/gemini';

interface Props {
  question: Question;
  language: Language;
  hiddenOptions: string[];
  isDoubleDipActive: boolean;
  visibleOptions: string[];
  isSpeaking: boolean;
  onAnswer: (correct: boolean, isFirstAttemptOfDoubleDip: boolean) => void;
  onRepeat: () => void;
  onVoiceCommand: (intentData: any) => void;
}

const QuizArea: React.FC<Props> = ({ 
  question, language, hiddenOptions, isDoubleDipActive, visibleOptions, isSpeaking, onAnswer, onRepeat, onVoiceCommand 
}) => {
  const [selected, setSelected] = useState<string | null>(null);
  const [locked, setLocked] = useState(false);
  const [showResult, setShowResult] = useState(false);
  const [failedOptions, setFailedOptions] = useState<string[]>([]);

  const [isRecording, setIsRecording] = useState(false);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  useEffect(() => {
    setSelected(null);
    setLocked(false);
    setShowResult(false);
    setFailedOptions([]);
  }, [question]);

  const handleOptionClick = (key: string) => {
    if (!locked && !showResult && !hiddenOptions.includes(key) && !failedOptions.includes(key)) {
      setSelected(key);
    }
  };

  const lockAnswer = (key?: string) => {
    const target = key || selected;
    if (!target) return;

    setSelected(target);
    setLocked(true);

    setTimeout(() => {
      const isCorrect = target === question.correctAnswer;
      setShowResult(true);

      if (isCorrect) {
        setTimeout(() => onAnswer(true, false), 2500);
      } else {
        if (isDoubleDipActive && failedOptions.length === 0) {
          setTimeout(() => {
            setFailedOptions(prev => [...prev, target]);
            setSelected(null);
            setLocked(false);
            setShowResult(false);
            onAnswer(false, true);
          }, 1500);
        } else {
          setTimeout(() => onAnswer(false, false), 3500);
        }
      }
    }, 2000);
  };

  const startRecording = async () => {
    if (locked || showResult || isRecording || isTranscribing) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (e) => e.data.size > 0 && audioChunksRef.current.push(e.data);
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64String = (reader.result as string).split(',')[1];
          if (!base64String) return;
          setIsTranscribing(true);
          const command = await recognizeVoiceCommand(base64String, 'audio/webm', language);
          setIsTranscribing(false);
          if (command && command.intent !== 'NONE') {
            if (command.intent === 'SELECT_OPTION') setSelected(command.target);
            if (command.intent === 'LOCK_OPTION') lockAnswer(command.target);
            onVoiceCommand(command);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
      setTimeout(() => stopRecording(), 3000);
    } catch (err) { console.error(err); }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current?.state === 'recording') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const getOptionClass = (key: string) => {
    if (hiddenOptions.includes(key)) return 'opacity-0 pointer-events-none';
    if (failedOptions.includes(key)) return 'opacity-40 grayscale bg-red-950/20';
    if (showResult) {
      if (key === question.correctAnswer) return 'option-correct scale-105 z-10';
      if (key === selected) return 'option-wrong';
      return 'opacity-20 grayscale blur-[1px]';
    }
    if (selected === key) return locked ? 'option-selected animate-pulse scale-105' : 'option-selected';
    return 'hover:bg-blue-900/40 border-[#d4af37]/40';
  };

  const isHindi = language === Language.HINDI;

  // Show "Voice Generating" status only if speaking is initiated but NO options are revealed yet
  const isGeneratingVoice = isSpeaking && visibleOptions.length === 0;

  return (
    <div className="flex flex-col items-center justify-center p-2 md:p-4 space-y-4 w-full max-w-5xl mx-auto">

      {/* Voice Generation Alert - Appear only during the preparation phase */}
      <div className={`transition-all duration-500 overflow-hidden ${isGeneratingVoice ? 'h-10 opacity-100 mb-2' : 'h-0 opacity-0 mb-0'}`}>
        <div className="bg-blue-900/60 border border-[#d4af37]/40 px-6 py-1 rounded-full backdrop-blur-md flex items-center space-x-3">
          <div className="w-2 h-2 bg-[#d4af37] rounded-full animate-pulse"></div>
          <span className="gold-text text-sm font-black uppercase tracking-widest italic animate-pulse">
            {isHindi ? 'होस्ट आवाज़ तैयार कर रहे हैं, कृपया प्रतीक्षा करें...' : 'Host is preparing the voice, please wait...'}
          </span>
          <div className="flex space-x-1">
             <div className="w-1 h-1 bg-white rounded-full animate-bounce [animation-delay:-0.3s]"></div>
             <div className="w-1 h-1 bg-white rounded-full animate-bounce [animation-delay:-0.15s]"></div>
             <div className="w-1 h-1 bg-white rounded-full animate-bounce"></div>
          </div>
        </div>
      </div>

      <div className="flex flex-col items-center mb-1 animate-fade-in">
        <div className={`relative w-20 h-20 md:w-28 md:h-28 rounded-full border-4 overflow-hidden transition-all duration-300 ${isSpeaking ? 'animate-speaking border-white scale-110 shadow-[0_0_30px_rgba(255,255,255,0.4)]' : 'border-[#d4af37]'}`}>
          <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Host&skinColor=ae5d29&topType=shortHair&hairColor=70b2d9&facialHairType=beardLight" alt="Host" className="w-full h-full object-cover" />
        </div>
      </div>

      <div className="w-full p-6 md:p-10 bg-black/80 border-2 border-[#d4af37] rounded-3xl text-center shadow-2xl relative overflow-hidden group">
        <div className="absolute inset-0 bg-gradient-to-br from-[#d4af37]/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
        <h2 className="text-xl md:text-3xl lg:text-4xl font-bold text-white leading-relaxed drop-shadow-lg">{question.text}</h2>
      </div>

      <div className="flex items-center justify-center space-x-12 mt-2">
        <button 
          onClick={isRecording ? stopRecording : startRecording} 
          disabled={locked || showResult || isSpeaking} 
          className={`w-14 h-14 flex items-center justify-center rounded-full border-2 transition-all ${
            isSpeaking ? 'opacity-20 grayscale border-gray-600' :
            isRecording ? 'bg-red-500 animate-mic-pulse border-white' : 'bg-black/60 border-[#d4af37]/60 hover:scale-110'
          }`}
        >
          <i className={`fas ${isTranscribing ? 'fa-circle-notch fa-spin' : isRecording ? 'fa-stop' : 'fa-microphone'} text-white`}></i>
        </button>
        <button 
          onClick={onRepeat} 
          disabled={locked || showResult || isSpeaking} 
          className={`w-14 h-14 flex items-center justify-center rounded-full border-2 transition-all ${
            isSpeaking ? 'opacity-20 grayscale border-gray-600' : 'border-[#d4af37]/60 bg-black/60 hover:scale-110'
          }`}
        >
          <i className="fas fa-redo gold-text"></i>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6 w-full max-w-4xl mt-4">
        {Object.entries(question.options).map(([key, value]) => (
          <button
            key={key}
            onClick={() => handleOptionClick(key)}
            disabled={locked || showResult || !visibleOptions.includes(key)}
            className={`option-button flex items-center px-6 py-4 text-white text-lg md:text-xl font-bold transition-all duration-500 ${!visibleOptions.includes(key) ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'} ${getOptionClass(key)}`}
          >
            <span className="mr-6 gold-text text-2xl drop-shadow-[0_0_5px_rgba(212,175,55,0.5)]">{key}:</span>
            <span className="text-left leading-tight">{value}</span>
          </button>
        ))}
      </div>

      <div className="h-20 flex items-center justify-center mt-2">
        {selected && !locked && !showResult && (
          <button onClick={() => lockAnswer()} className="bg-gradient-to-r from-orange-600 to-orange-400 text-white font-black py-3 px-16 rounded-full text-2xl shadow-2xl animate-bounce uppercase tracking-widest border border-white/20">
            {isHindi ? 'लॉक करें!' : 'Lock It!'}
          </button>
        )}
      </div>
    </div>
  );
};

export default QuizArea;

import { GoogleGenAI, Modality } from "@google/genai";
import { Language, Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

let audioContext: AudioContext | null = null;
let currentSource: AudioBufferSourceNode | null = null;

const initAudioContext = () => {
  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  }
  return audioContext;
};

function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const stopSpeech = () => {
  if (currentSource) {
    try {
      currentSource.stop();
    } catch (e) {}
    currentSource = null;
  }
};

/**
 * ULTRA-LOW LATENCY: Fetches question and options audio in one stream.
 * Predicts timings to reveal options one-by-one.
 */
export const speakFullQuestionSequence = async (
  level: number,
  question: Question,
  lang: Language,
  onOptionReveal: (key: string) => void,
  onStart?: () => void
): Promise<void> => {
  stopSpeech();
  const ctx = initAudioContext();
  const isHindi = lang === Language.HINDI;

  const text = isHindi
    ? `${question.text}। विकल्प A: ${question.options.A}। विकल्प B: ${question.options.B}। विकल्प C: ${question.options.C}। विकल्प D: ${question.options.D}।`
    : `${question.text}. Option A: ${question.options.A}. Option B: ${question.options.B}. Option C: ${question.options.C}. Option D: ${question.options.D}.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Fenrir' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), ctx, 24000, 1);

      // Notify that reading is starting now!
      if (onStart) onStart();

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.start();
      currentSource = source;

      const qRatio = question.text.length / text.length;
      const qDuration = audioBuffer.duration * qRatio;
      const remaining = audioBuffer.duration - qDuration;
      const optDuration = remaining / 4;

      setTimeout(() => onOptionReveal('A'), qDuration * 1000);
      setTimeout(() => onOptionReveal('B'), (qDuration + optDuration) * 1000);
      setTimeout(() => onOptionReveal('C'), (qDuration + optDuration * 2) * 1000);
      setTimeout(() => onOptionReveal('D'), (qDuration + optDuration * 3) * 1000);

      return new Promise((resolve) => {
        source.onended = () => {
          currentSource = null;
          resolve();
        };
      });
    }
  } catch (error) {
    console.error("TTS Pipeline Error:", error);
    if (onStart) onStart();
    onOptionReveal('A'); onOptionReveal('B'); onOptionReveal('C'); onOptionReveal('D');
  }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import LanguageSelection from './components/LanguageSelection';
import NameInput from './components/NameInput';
import Disclaimer from './components/Disclaimer';
import Sidebar from './components/Sidebar';
import QuizArea from './components/QuizArea';
import Lifelines from './components/Lifelines';
import GameOver from './components/GameOver';
import { Language, GameStatus, Question, Lifelines as LifelinesType, PollData } from './types';
import { fetchQuestion } from './services/gemini';
import { getTimerForLevel, MONEY_TREE } from './constants';
import { stopSpeech, speakFullQuestionSequence } from './services/tts';

const App: React.FC = () => {
  const [status, setStatus] = useState<GameStatus>(GameStatus.NAME_INPUT);
  const [playerName, setPlayerName] = useState('');
  const [language, setLanguage] = useState<Language>(Language.ENGLISH);
  const [level, setLevel] = useState(1);
  const [question, setQuestion] = useState<Question | null>(null);
  const [loading, setLoading] = useState(false);
  const [isVoiceLoading, setIsVoiceLoading] = useState(false);
  const [timeLeft, setTimeLeft] = useState<number | null>(null);
  const [maxTime, setMaxTime] = useState<number | null>(null);
  const [hiddenOptions, setHiddenOptions] = useState<string[]>([]);
  const [visibleOptions, setVisibleOptions] = useState<string[]>([]);
  const [pollData, setPollData] = useState<PollData | null>(null);
  const [isDoubleDipActive, setIsDoubleDipActive] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isVoiceEnabled, setIsVoiceEnabled] = useState(true);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [showQuitConfirm, setShowQuitConfirm] = useState(false);
  const [canStartTimer, setCanStartTimer] = useState(false);
  const [lifelines, setLifelines] = useState<LifelinesType>({
    fiftyFifty: true, audiencePoll: true, doubleDip: true, flipQuestion: true
  });

  const timerRef = useRef<any>(null);

  const startUnifiedSpeech = useCallback(async (q: Question, l: number, lang: Language, name: string) => {
    setIsSpeaking(true);
    setIsVoiceLoading(true); // Start loading state
    setVisibleOptions([]); 
    setCanStartTimer(false);

    await speakFullQuestionSequence(
      l, q, lang, 
      (key) => {
        setVisibleOptions(prev => [...new Set([...prev, key])]);
      },
      () => {
        setIsVoiceLoading(false); // Playback started, hide the message
      }
    );

    setIsSpeaking(false);
    setIsVoiceLoading(false);
    setCanStartTimer(true); 
  }, []);

  const loadQuestion = async (currLevel: number, lang: Language) => {
    stopSpeech();
    setLoading(true);
    setIsVoiceLoading(false);
    setVisibleOptions([]);
    setHiddenOptions([]);
    setPollData(null);
    setIsDoubleDipActive(false);
    setCanStartTimer(false);

    try {
      const q = await fetchQuestion(currLevel, lang);
      setQuestion(q);
      const initialTime = getTimerForLevel(currLevel);
      setMaxTime(initialTime);
      setTimeLeft(initialTime);
      setLoading(false);

      if (isVoiceEnabled) {
        startUnifiedSpeech(q, currLevel, lang, playerName);
      } else {
        setVisibleOptions(['A', 'B', 'C', 'D']);
        setCanStartTimer(true);
      }
    } catch (error) { setLoading(false); }
  };

  useEffect(() => {
    if (status === GameStatus.PLAYING && canStartTimer && timeLeft !== null && timeLeft > 0 && !loading) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev === null || prev <= 1) { clearInterval(timerRef.current); return 0; }
          return prev - 1;
        });
      }, 1000);
    } else if (status === GameStatus.PLAYING && timeLeft === 0 && canStartTimer) {
      handleAnswer(false, false);
    }
    return () => clearInterval(timerRef.current);
  }, [status, timeLeft, loading, canStartTimer]);

  const handleVoiceCommand = (intentData: any) => {
    if (intentData.intent === 'USE_LIFELINE') useLifeline(intentData.target);
    if (intentData.intent === 'QUIT_GAME') setShowQuitConfirm(true);
  };

  const handleAnswer = (isCorrect: boolean, isFirstAttemptOfDoubleDip: boolean) => {
    stopSpeech();
    if (isFirstAttemptOfDoubleDip) return;
    clearInterval(timerRef.current);
    if (isCorrect) {
      setTimeout(() => {
        if (level === 15) setStatus(GameStatus.WON);
        else { setLevel(l => l + 1); loadQuestion(level + 1, language); }
      }, 2000);
    } else {
      setTimeout(() => setStatus(GameStatus.LOST), 1500);
    }
  };

  const useLifeline = (type: keyof LifelinesType) => {
    if (!question || loading) return;
    setLifelines(prev => ({ ...prev, [type]: false }));
    if (type === 'fiftyFifty') {
      const incorrect = Object.keys(question.options).filter(k => k !== question.correctAnswer).sort(() => 0.5 - Math.random());
      setHiddenOptions(incorrect.slice(0, 2));
    } else if (type === 'doubleDip') setIsDoubleDipActive(true);
    else if (type === 'flipQuestion') loadQuestion(level, language);
    else if (type === 'audiencePoll') {
       const correctKey = question.correctAnswer;
       const data = { A: 10, B: 10, C: 10, D: 10 };
       data[correctKey as keyof PollData] = 70;
       setPollData(data);
    }
  };

  const handleQuit = () => { stopSpeech(); setStatus(GameStatus.LOST); setShowQuitConfirm(false); };

  const isHindi = language === Language.HINDI;

  if (status === GameStatus.NAME_INPUT) return <NameInput onNameSubmit={(n) => { setPlayerName(n); setStatus(GameStatus.LANGUAGE_SELECT); }} />;
  if (status === GameStatus.LANGUAGE_SELECT) return <LanguageSelection onSelect={(l) => { setLanguage(l); setStatus(GameStatus.DISCLAIMER); }} />;
  if (status === GameStatus.WON || status === GameStatus.LOST) return <GameOver isWon={status === GameStatus.WON} levelReached={level} language={language} onRestart={() => window.location.reload()} />;

  const currentAmount = MONEY_TREE.find(l => l.id === level)?.amount || "₹0";

  return (
    <div className="min-h-screen kbc-bg flex flex-col md:flex-row relative text-white overflow-hidden">
      {status === GameStatus.DISCLAIMER && <Disclaimer language={language} onStart={() => { setStatus(GameStatus.PLAYING); loadQuestion(1, language); }} />}

      {showQuitConfirm && (
        <div className="fixed inset-0 z-[300] bg-black/95 flex items-center justify-center p-6 backdrop-blur-xl animate-fade-in">
          <div className="bg-[#001a33] p-10 rounded-3xl gold-border max-w-md w-full text-center space-y-8 animate-scale-in">
            <h2 className="text-3xl font-black gold-text uppercase italic">{isHindi ? 'खेल छोड़ना?' : 'Quit Game?'}</h2>
            <p className="text-xl text-blue-100">{isHindi ? 'क्या आप वाकई खेल छोड़ना चाहते हैं?' : 'Are you sure you want to leave the game?'}</p>
            <div className="flex gap-4">
              <button onClick={handleQuit} className="flex-1 bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-xl uppercase transition-all shadow-lg shadow-red-900/40">Yes, Quit</button>
              <button onClick={() => setShowQuitConfirm(false)} className="flex-1 bg-green-600 hover:bg-green-700 text-white font-bold py-4 rounded-xl uppercase transition-all shadow-lg shadow-green-900/40">Stay</button>
            </div>
          </div>
        </div>
      )}

      {/* Side Control (Sidebar Toggle for Mobile) */}
      <div className="md:hidden fixed top-24 left-4 z-[60]">
         <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="w-12 h-12 bg-blue-900/90 border border-[#d4af37] rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform">
            <i className={`fas ${isSidebarOpen ? 'fa-times' : 'fa-list-ul'} gold-text text-xl`}></i>
         </button>
      </div>

      <div className="flex-grow flex flex-col relative min-h-screen z-10">
        <header className="w-full flex justify-between items-center px-4 md:px-8 py-3 bg-black/60 border-b border-[#d4af37]/30 backdrop-blur-md sticky top-0 z-[50]">
          <div className="flex items-center space-x-3">
            <div className="flex flex-col">
              <span className="text-gray-400 font-bold uppercase text-[9px] tracking-widest">{playerName} • LEVEL {level}</span>
              <span className="gold-text font-black text-lg md:text-2xl leading-none">{currentAmount}</span>
            </div>
          </div>

          <div className="flex items-center space-x-3 md:space-x-8">
            <button 
              onClick={() => setIsVoiceEnabled(!isVoiceEnabled)} 
              className={`w-10 h-10 md:w-12 md:h-12 rounded-full flex items-center justify-center border transition-all ${isVoiceEnabled ? 'bg-[#d4af37] text-black border-white' : 'bg-gray-800 text-gray-400 border-gray-700'}`}
            >
              <i className={`fas ${isVoiceEnabled ? 'fa-volume-up' : 'fa-volume-mute'}`}></i>
            </button>

            <div className={`relative w-12 h-12 md:w-16 md:h-16 flex items-center justify-center rounded-full border-2 ${timeLeft && timeLeft <= 10 ? 'animate-timer-critical border-red-500' : 'animate-timer-pulse border-blue-400'}`}>
               <span className={`text-xl font-black ${timeLeft && timeLeft <= 10 ? 'text-red-200' : 'text-blue-100'}`}>{timeLeft ?? '∞'}</span>
            </div>

            <button 
              onClick={() => setShowQuitConfirm(true)} 
              className="hidden md:block bg-red-900/60 border border-red-500/60 text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase hover:bg-red-600 transition-all"
            >
              QUIT
            </button>
          </div>
        </header>

        <main className="flex-grow flex flex-col items-center justify-start p-2 md:p-6 overflow-y-auto w-full">
          {loading ? (
            <div className="flex flex-col items-center justify-center flex-grow space-y-6">
              <div className="w-16 h-16 border-4 border-t-[#d4af37] border-white/10 rounded-full animate-spin"></div>
              <p className="gold-text font-black uppercase tracking-widest animate-pulse">Wait for the Hot Seat...</p>
            </div>
          ) : question ? (
            <div className="w-full flex flex-col items-center space-y-2 md:space-y-4 animate-fade-in max-w-6xl mx-auto">

              <div className="w-full mt-2">
                <Lifelines lifelines={lifelines} onUse={useLifeline} disabled={loading || isSpeaking} />
              </div>

              <div className="w-full">
                <QuizArea 
                  question={question} 
                  language={language} 
                  hiddenOptions={hiddenOptions} 
                  isDoubleDipActive={isDoubleDipActive} 
                  visibleOptions={visibleOptions} 
                  isSpeaking={isSpeaking}
                  isVoiceLoading={isVoiceLoading}
                  onAnswer={handleAnswer} 
                  onRepeat={() => startUnifiedSpeech(question, level, language, playerName)}
                  onVoiceCommand={handleVoiceCommand}
                />
              </div>
            </div>
          ) : null}
        </main>
      </div>

      <aside className={`fixed md:relative top-0 right-0 h-screen w-72 lg:w-80 transition-transform duration-300 z-[100] md:translate-x-0 ${isSidebarOpen ? 'translate-x-0 shadow-2xl' : 'translate-x-full md:translate-x-0'}`}>
        <Sidebar currentLevel={level} />
        {isSidebarOpen && (
          <button onClick={() => setIsSidebarOpen(false)} className="md:hidden absolute -left-12 top-24 w-12 h-12 bg-blue-950 rounded-l-full flex items-center justify-center border-l border-y border-[#d4af37] shadow-lg">
            <i className="fas fa-chevron-right gold-text"></i>
          </button>
        )}
      </aside>

      {pollData && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-4 animate-fade-in">
          <div className="bg-[#000d1a] p-6 md:p-12 rounded-3xl gold-border max-w-lg w-full text-center space-y-6 animate-scale-in">
            <h3 className="gold-text text-2xl md:text-3xl font-black uppercase italic tracking-widest">{isHindi ? 'ऑडियन्स पोल' : 'Audience Poll'}</h3>
            <div className="flex items-end justify-around h-48 md:h-64 gap-3 md:gap-4">
              {Object.entries(pollData).map(([key, value]) => (
                <div key={key} className="flex flex-col items-center w-full">
                  <span className="text-blue-100 text-[10px] md:text-sm font-bold mb-1">{value}%</span>
                  <div className="relative w-full bg-blue-900/40 rounded-t-lg border border-white/10 overflow-hidden" style={{ height: `${value}%` }}>
                    <div className="absolute inset-0 bg-gradient-to-t from-blue-700 to-cyan-400 animate-pulse"></div>
                  </div>
                  <div className="w-full mt-2 bg-white text-black font-black py-1 rounded text-sm md:text-lg">{key}</div>
                </div>
              ))}
            </div>
            <button onClick={() => setPollData(null)} className="bg-[#d4af37] text-black font-black py-3 px-12 rounded-full hover:scale-105 transition-all uppercase shadow-lg">
              {isHindi ? 'आगे बढ़ें' : 'CONTINUE'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

